def pie_format_update(rec, event, price):
    elapsed_min = int((time.time() - float(rec.get("created_ts", time.time()))) / 60)
    return f"""
📊 PIE SINYAL TAKIP - {event}

Coin: {rec.get('symbol')}
Mod: {rec.get('module')}
Giris: {pie_float(rec.get('entry')):.8f}
Anlik: {pie_float(price):.8f}
Max: %{pie_float(rec.get('max_gain_pct')):.2f}
DD: %{pie_float(rec.get('max_dd_pct')):.2f}
Sure: {elapsed_min} dk
Elite: {rec.get('elite_score')}/100 | Guven: {rec.get('elite_confidence_score')}/100
""".strip()


def pie_update_open_signals(chat_id=None):
    if not PIE_ENABLED:
        return
    records = pie_load_records()
    if not records:
        return
    changed = False
    now_ts = time.time()
    for rec in records:
        if rec.get("status") not in ("OPEN", "TP1", "TP2"):
            continue
        if now_ts - float(rec.get("last_update_ts", 0) or 0) < PIE_UPDATE_COOLDOWN_SECONDS:
            continue
        symbol = rec.get("symbol")
        entry = pie_float(rec.get("entry"))
        if not symbol or entry <= 0:
            continue
        try:
            ticker = exchange.fetch_ticker(symbol)
            price = pie_float(ticker.get("last") or ticker.get("close") or ticker.get("bid") or ticker.get("ask"))
            if price <= 0:
                continue
            rec["last_price"] = price
            rec["last_update_ts"] = now_ts
            rec["max_price"] = max(pie_float(rec.get("max_price"), entry), price)
            rec["min_price"] = min(pie_float(rec.get("min_price"), entry), price)
            rec["max_gain_pct"] = ((rec["max_price"] - entry) / entry * 100) if entry else 0
            rec["max_dd_pct"] = ((rec["min_price"] - entry) / entry * 100) if entry else 0
            event = None
            if price <= pie_float(rec.get("stop")) and not rec.get("tp1_hit"):
                rec["stop_hit"] = True; rec["status"] = "STOP"; event = "STOP"
            elif price >= pie_float(rec.get("tp3")):
                rec["tp1_hit"] = rec["tp2_hit"] = rec["tp3_hit"] = True; rec["status"] = "TP3"; event = "TP3"
            elif price >= pie_float(rec.get("tp2")) and not rec.get("tp2_hit"):
                rec["tp1_hit"] = rec["tp2_hit"] = True; rec["status"] = "TP2"; event = "TP2"
            elif price >= pie_float(rec.get("tp1")) and not rec.get("tp1_hit"):
                rec["tp1_hit"] = True; rec["status"] = "TP1"; event = "TP1"
            elif (now_ts - float(rec.get("created_ts", now_ts))) > PIE_MAX_TRACK_HOURS * 3600:
                rec["status"] = "EXPIRED"; event = "SURE DOLDU"
            if event:
                send_telegram(pie_format_update(rec, event, price), chat_id)
            changed = True
        except Exception as e:
            print("PIE update hata:", symbol, e, flush=True)
    if changed:
        pie_save_records(records)


def can_send(cache, key, cooldown):
    now = time.time()
    if key in cache and now - cache[key] < cooldown:
        return False
    cache[key] = now
    return True


def rsi(series, length=14):
    delta = series.diff()
    gain = delta.clip(lower=0).rolling(length).mean()
    loss = -delta.clip(upper=0).rolling(length).mean()
    rs = gain / loss.replace(0, np.nan)
    return 100 - (100 / (1 + rs))


def indicators(df):
    close = df["close"]
    high = df["high"]
    low = df["low"]
    volume = df["volume"]
    df["ema9"] = close.ewm(span=9, adjust=False).mean()
    df["ema21"] = close.ewm(span=21, adjust=False).mean()
    df["ema200"] = close.ewm(span=200, adjust=False).mean()
    df["vol_avg"] = volume.rolling(20).mean()
    df["rsi"] = rsi(close)
    ema12 = close.ewm(span=12, adjust=False).mean()
    ema26 = close.ewm(span=26, adjust=False).mean()
    df["macd"] = ema12 - ema26
    df["macd_signal"] = df["macd"].ewm(span=9, adjust=False).mean()
    basis = close.rolling(20).mean()
    dev = close.rolling(20).std()
    df["bb_middle"] = basis
    df["bb_upper"] = basis + dev * 2
    df["bb_lower"] = basis - dev * 2
    df["bb_width"] = (df["bb_upper"] - df["bb_lower"]) / basis.replace(0, np.nan)
    candle_range = (high - low).replace(0, np.nan)
    df["body_ratio"] = (close - df["open"]).abs() / candle_range
    df["upper_wick"] = (high - pd.concat([df["open"], close], axis=1).max(axis=1)) / candle_range
    df["lower_wick"] = (pd.concat([df["open"], close], axis=1).min(axis=1) - low) / candle_range
    df["recovery_ratio"] = (close - low) / candle_range
    df["obv"] = np.where(close > close.shift(1), volume, np.where(close < close.shift(1), -volume, 0)).cumsum()
    return df.dropna().copy()


def fetch_df(symbol, timeframe, limit=120):
    for _ in range(3):
        try:
            data = exchange.fetch_ohlcv(symbol, timeframe, limit=limit)
            if not data or len(data) < 40:
                return None
            df = pd.DataFrame(data, columns=["time", "open", "high", "low", "close", "volume"])
            return indicators(df)
        except Exception as e:
            print("Fetch hata:", symbol, timeframe, e, flush=True)
            time.sleep(1.5)
    return None


def get_funding(symbol):
    try:
        data = exchange.fetch_funding_rate(symbol)
        rate = data.get("fundingRate") or 0
        if -0.001 <= rate <= 0.0015:
            return {"ok": True, "rate": rate, "status": "NORMAL"}
        if rate > 0.0015:
            return {"ok": False, "rate": rate, "status": "LONG KALABALIK"}
        return {"ok": True, "rate": rate, "status": "SHORT BASKI"}
    except Exception:
        return {"ok": True, "rate": 0, "status": "VERI YOK"}


def btc_filter():
    df = fetch_df("BTC/USDT:USDT", "15m", 120)
    if df is None:
        return True, "BTC VERI YOK"
    last = df.iloc[-1]
    ok = last.close > last.ema21 and last.macd > last.macd_signal and last.rsi >= 43
    return ok, "BTC DESTEKLI" if ok else "BTC ZAYIF"


def build_universe():
    try:
        markets = exchange.load_markets()
        symbols = [s for s in markets if s.endswith("/USDT:USDT") and markets[s].get("active", True)]
        tickers = exchange.fetch_tickers(symbols)
        rows = []
        for s in symbols:
            if is_excluded_symbol(s):
                continue
            t = tickers.get(s, {})
            qv = t.get("quoteVolume") or 0
            pct = t.get("percentage") or 0
            last = t.get("last") or 0
            high = t.get("high") or 0
            low = t.get("low") or 0
            if last <= 0 or high <= 0 or low <= 0 or qv <= 0:
                continue
            volatility = ((high - low) / last) * 100
            if qv < MIN_UNIVERSE_QV or volatility < MIN_UNIVERSE_VOLATILITY:
                continue
            rows.append({"symbol": s, "qv": qv, "pct": pct, "last": last, "high": high, "low": low, "volatility": volatility})
        if not rows:
            return []
        df = pd.DataFrame(rows)
        df["pct_rank"] = df["pct"].rank(pct=True) * 100
        df["vol_rank"] = df["qv"].rank(pct=True) * 100
        df["volatility_rank"] = df["volatility"].rank(pct=True) * 100
        df["rs_score"] = df["pct_rank"] * 0.45 + df["vol_rank"] * 0.30 + df["volatility_rank"] * 0.25
        df = df.sort_values(["rs_score", "qv"], ascending=False).head(MAX_SYMBOLS)
        result = df.to_dict("records")
        print("RS evren secildi:", len(result), flush=True)
        return result
    except Exception as e:
        print("Universe hata:", e, flush=True)
        return []


def fib_targets(df, lookback=60):
    recent = df.tail(lookback)
    low = recent["low"].min()
    high = recent["high"].max()
    if high - low <= 0:
        return None
    return {"low": low, "high": high}




def recent_price_gains(df, price=None):
    """
    FOMO filtresi icin son 15m / 30m hareketi olcer.
    Ornek: 0.070 -> 0.080 olmus coin artik AL ONAY icin gec sayilir.
    """
    if df is None or len(df) < 4:
        return {"price_gain_15m": 0, "price_gain_30m": 0}
    now_price = price if price is not None else df["close"].iloc[-1]
    p15 = df["close"].iloc[-2]
    p30 = df["close"].iloc[-3]
    gain15 = ((now_price - p15) / p15) * 100 if p15 > 0 else 0
    gain30 = ((now_price - p30) / p30) * 100 if p30 > 0 else 0
    return {"price_gain_15m": gain15, "price_gain_30m": gain30}


def fomo_gain_pct(d):
    """
    Gec kalmis patlama mumunu yakalar.
    price_gain_from_first + son 15/30 dk hareket + dipten uzaklik birlikte degerlendirilir.
    """
    if not d:
        return 999
    values = []
    if "price_gain_from_first" in d:
        values.append(d.get("price_gain_from_first", 0))
    values.append(d.get("price_gain_15m", 0))
    values.append(d.get("price_gain_30m", 0) * 0.70)
    if d.get("dist_from_low", 999) < 999:
        values.append(d.get("dist_from_low", 0) * 0.75)
    return max(values) if values else 999



def enrich_market_impact(d, daily_qv):
    """
    Coinin kendi 24s hacmine gore mevcut USDT hacminin ne kadar etkili oldugunu olcer.
    Mutlak hacim tek basina yetmez: 100K USDT kucuk coinde buyuk, dev hacimli coinde zayif kalabilir.
    market_impact_pct = sinyal_usdt_hacim / 24s_quote_volume * 100
    """
    if not d:
        return d

    try:
        daily_qv = float(daily_qv or 0)
    except Exception:
        daily_qv = 0

    signal_usdt = (
        d.get("usdt_vol")
        or d.get("usdt_vol_15m")
        or d.get("usdt_vol_1h")
        or 0
    )

    try:
        signal_usdt = float(signal_usdt or 0)
    except Exception:
        signal_usdt = 0

    market_impact_pct = (signal_usdt / daily_qv * 100) if daily_qv > 0 else 0

    # 0-100 arasi okunabilir skor. Esik yavas artar; dusuk hacimli coinde gercek etkiyi odullendirir.
    if market_impact_pct >= 2.0:
        market_impact_score = 100
    elif market_impact_pct >= 1.0:
        market_impact_score = 90
    elif market_impact_pct >= 0.50:
        market_impact_score = 78
    elif market_impact_pct >= 0.25:
        market_impact_score = 65
    elif market_impact_pct >= 0.12:
        market_impact_score = 50
    elif market_impact_pct >= 0.06:
        market_impact_score = 35
    else:
        market_impact_score = 15 if market_impact_pct > 0 else 0

    d["daily_qv"] = daily_qv
    d["signal_usdt_vol"] = signal_usdt
    d["market_impact_pct"] = market_impact_pct
    d["market_impact_score"] = market_impact_score

    # Para etkisi + hacim gucu + coin hacmine gore etkiyi tek yerde toplar.
    d["relative_money_power"] = d.get("money_impact", 0) * (1 + market_impact_pct)
    return d



def money_quality_upgrade(d):
    """
    PARA KALITESI TERFISI:
    H/USDT gibi tek radarda kalip da cok guclu para girisi olan coinleri Elite adayina tasir.
    Radar sayisi az olsa bile; hacim coin icin gercekten buyukse, fiyat cok kacmamis ise ve RSI sisik degilse calisir.
    """
    if not d:
        return False

    module = d.get("module", "UNKNOWN")
    money = d.get("money_impact", 0)
    power = d.get("volume_power", 0)
    usdt_vol = d.get("usdt_vol", d.get("signal_usdt_vol", 0))
    market_impact_pct = d.get("market_impact_pct", 0)
    rsi_value = d.get("rsi", d.get("rsi15", 0))
    dist = d.get("dist_from_low", 999)
    price_gain_15m = d.get("price_gain_15m", 0)
    price_gain_30m = d.get("price_gain_30m", 0)

    # Momentum tek basina terfi almasin; zaten gec kalma riski yuksek.
    if module == "MOMENTUM":
        return False

    if rsi_value >= 74:
        return False

    # H tipi: cok guclu para var ama daha fomo olmamis.
    strong_absolute_money = (
        usdt_vol >= 5_000_000
        and money >= 2.8
        and power >= 10
    )

    # Kucuk/orta hacimli coinde 24s hacme gore cok buyuk etki.
    strong_relative_money = (
        market_impact_pct >= 1.0
        and usdt_vol >= 75_000
        and money >= 2.0
        and power >= 5.0
    )

    # Erkenlik korunacak: coktan kacmis coin terfi almasin.
    early_enough = (
        dist <= 18
        and price_gain_15m <= 8
        and price_gain_30m <= 15
    )

    return early_enough and (strong_absolute_money or strong_relative_money)


def calculate_support_resistance(symbol, price=None):
    """
    V39 EN YAKIN DESTEK / DIRENC KATMANI:
    Eski sistem 15m/1H penceresindeki en buyuk tepeyi direnc aliyordu.
    Bu versiyon fiyat USTUNDEKI en yakin 15m/1H swing high'i direnc,
    fiyat ALTINDAKI en yakin 15m/1H swing low'u destek olarak secer.
    Boylece saatlik ara direncler de Elite Hazirlik / Gold / AL mesajlarinda gorunur.
    """
    out = {
        "sr_ok": False,
        "sr_resistance": 0.0,
        "sr_support": 0.0,
        "sr_resistance_distance_pct": 999.0,
        "sr_support_distance_pct": 999.0,
        "sr_breakout": False,
        "sr_near_resistance": False,
        "sr_very_near_resistance": False,
        "sr_support_close": False,
        "sr_status": "VERI YOK",
        "sr_penalty": 0,
        "sr_bonus": 0,
    }
    try:
        df15 = fetch_df(symbol, "15m", 160)
        df1h = fetch_df(symbol, "1h", 120)
        if df15 is None or df1h is None or len(df15) < 60 or len(df1h) < 30:
            return out

        live_price = float(price or df15["close"].iloc[-1])
        if live_price <= 0:
            return out

        # Son mumu disarida birakiyoruz; aktif mum fitili sahte direnc/destek yapmasin.
        h15 = df15["high"].iloc[-49:-1]
        l15 = df15["low"].iloc[-49:-1]
        h1 = df1h["high"].iloc[-25:-1]
        l1 = df1h["low"].iloc[-25:-1]

        high_values = [float(x) for x in h15.dropna().tolist()] + [float(x) for x in h1.dropna().tolist()]
        low_values = [float(x) for x in l15.dropna().tolist()] + [float(x) for x in l1.dropna().tolist()]

        # En yakin direnç = fiyat ustundeki en dusuk swing high.
        highs_above = [x for x in high_values if x > live_price]
        # En yakin destek = fiyat altindaki en yuksek swing low.
        lows_below = [x for x in low_values if 0 < x < live_price]

        resistance = float(min(highs_above)) if highs_above else float(max(high_values)) if high_values else 0.0
        support = float(max(lows_below)) if lows_below else float(min(low_values)) if low_values else 0.0

        resistance_distance = ((resistance - live_price) / live_price * 100) if resistance > 0 else 999.0
        support_distance = ((live_price - support) / support * 100) if support > 0 else 999.0

        breakout = live_price > resistance * 1.002 if resistance > 0 else False
        very_near = (0 <= resistance_distance <= SR_RESISTANCE_VERY_NEAR_PCT)
        near = (0 <= resistance_distance <= SR_RESISTANCE_NEAR_PCT)
        warn = (0 <= resistance_distance <= SR_RESISTANCE_WARN_PCT)
        support_close = (0 <= support_distance <= SR_SUPPORT_CLOSE_PCT)

        penalty = 0
        bonus = 0
        if breakout:
            status = "DIRENC KIRILDI"
            bonus += SR_BREAKOUT_BONUS
        elif very_near:
            status = "DIRENC COK YAKIN"
            penalty += SR_NEAR_RESISTANCE_PENALTY
        elif near:
            status = "DIRENC YAKIN"
            penalty += int(SR_NEAR_RESISTANCE_PENALTY * 0.65)
        elif warn:
            status = "DIRENC BOLGESI"
            penalty += SR_WARN_RESISTANCE_PENALTY
        else:
            status = "DIRENC UZAK"

        if support_close:
            bonus += SR_SUPPORT_BONUS
        elif support_distance >= SR_SUPPORT_FAR_PCT and not breakout:
            penalty += SR_FLOATING_PENALTY

        out.update({
            "sr_ok": True,
            "sr_resistance": resistance,
            "sr_support": support,
            "sr_resistance_distance_pct": resistance_distance,
            "sr_support_distance_pct": support_distance,
            "sr_breakout": bool(breakout),
            "sr_near_resistance": bool(near),
            "sr_very_near_resistance": bool(very_near),
            "sr_support_close": bool(support_close),
            "sr_status": status,
            "sr_penalty": int(penalty),
            "sr_bonus": int(bonus),
        })
        return out
    except Exception as e:
        print("SR hesap hata:", symbol, e, flush=True)
        return out

def attach_support_resistance_context(symbol, d):
    if not d:
        return d
    price = d.get("price", d.get("entry", 0))
    sr = calculate_support_resistance(symbol, price)
    d.update(sr)
    return d


def fetch_mexc_orderbook_context(symbol, price=None):
    """
    V43 MEXC ORDER BOOK:
    Emir defterinden yakin alis/satis duvarlarini ve yukari/asagi likidite boslugunu olcer.
    MEXC'te order book ince oldugu icin bu skor PRE_ROCKET / SQUEEZE / EARLY_REVERSAL icin kritiktir.
    """
    cache_key = f"{symbol}_mexc_ob"
    now = time.time()
    cached = mexc_orderbook_cache.get(cache_key)
    if cached and now - cached.get("time", 0) < MEXC_OB_CACHE_SECONDS:
        return cached.get("data")

    out = {
        "orderbook_ok": False,
        "orderbook_score": 50,
        "orderbook_status": "ORDERBOOK VERI YOK",
        "bid_wall_price": 0.0,
        "bid_wall_usdt": 0.0,
        "bid_wall_distance_pct": 999.0,
        "ask_wall_price": 0.0,
        "ask_wall_usdt": 0.0,
        "ask_wall_distance_pct": 999.0,
        "bid_usdt_1pct": 0.0,
        "ask_usdt_1pct": 0.0,
        "book_imbalance": 1.0,
        "liquidity_gap_up": False,
        "liquidity_gap_down": False,
        "orderbook_block": False,
        "orderbook_reason": "VERI YOK",
        "liquidity_gap_score": 50,
    }

    try:
        ob = exchange.fetch_order_book(symbol, limit=MEXC_OB_LIMIT)
        bids = ob.get("bids", []) or []
        asks = ob.get("asks", []) or []
        if not bids or not asks:
            mexc_orderbook_cache[cache_key] = {"time": now, "data": out}
            return out

        live_price = float(price or 0)
        if live_price <= 0:
            live_price = float((bids[0][0] + asks[0][0]) / 2)
        if live_price <= 0:
            mexc_orderbook_cache[cache_key] = {"time": now, "data": out}
            return out

        def level_usdt(level):
            return float(level[0]) * float(level[1])

        bids_1 = [b for b in bids if 0 <= (live_price - float(b[0])) / live_price * 100 <= MEXC_OB_NEAR_PCT]
        asks_1 = [a for a in asks if 0 <= (float(a[0]) - live_price) / live_price * 100 <= MEXC_OB_NEAR_PCT]
        bids_2 = [b for b in bids if 0 <= (live_price - float(b[0])) / live_price * 100 <= MEXC_OB_WALL_LOOK_PCT]
        asks_2 = [a for a in asks if 0 <= (float(a[0]) - live_price) / live_price * 100 <= MEXC_OB_WALL_LOOK_PCT]

        bid_usdt_1 = sum(level_usdt(x) for x in bids_1)
        ask_usdt_1 = sum(level_usdt(x) for x in asks_1)
        imbalance = (bid_usdt_1 + 1.0) / (ask_usdt_1 + 1.0)

        avg_bid = (sum(level_usdt(x) for x in bids_2) / len(bids_2)) if bids_2 else 0.0
        avg_ask = (sum(level_usdt(x) for x in asks_2) / len(asks_2)) if asks_2 else 0.0
        bid_wall = max(bids_2, key=level_usdt) if bids_2 else None
        ask_wall = max(asks_2, key=level_usdt) if asks_2 else None

        bid_wall_price = float(bid_wall[0]) if bid_wall else 0.0
        ask_wall_price = float(ask_wall[0]) if ask_wall else 0.0
        bid_wall_usdt = level_usdt(bid_wall) if bid_wall else 0.0
        ask_wall_usdt = level_usdt(ask_wall) if ask_wall else 0.0
        bid_wall_dist = ((live_price - bid_wall_price) / live_price * 100) if bid_wall_price > 0 else 999.0
        ask_wall_dist = ((ask_wall_price - live_price) / live_price * 100) if ask_wall_price > 0 else 999.0

        real_bid_wall = bid_wall_usdt >= max(MEXC_OB_MIN_WALL_USDT, avg_bid * MEXC_OB_WALL_MULTIPLIER) if avg_bid > 0 else False
        real_ask_wall = ask_wall_usdt >= max(MEXC_OB_MIN_WALL_USDT, avg_ask * MEXC_OB_WALL_MULTIPLIER) if avg_ask > 0 else False

        liquidity_gap_up = bool(ask_usdt_1 > 0 and bid_usdt_1 > ask_usdt_1 * 1.8 and (not real_ask_wall or ask_wall_dist > 1.2))
        liquidity_gap_down = bool(bid_usdt_1 > 0 and ask_usdt_1 > bid_usdt_1 * 1.8 and (not real_bid_wall or bid_wall_dist > 1.2))

        score = 50
        gap_score = 50
        reasons = []
        if imbalance >= MEXC_OB_STRONG_IMBALANCE:
            score += 18; gap_score += 10; reasons.append("alis tarafi guclu")
        elif imbalance >= 1.15:
            score += 8; gap_score += 5; reasons.append("alis tarafi onde")
        elif imbalance <= MEXC_OB_WEAK_IMBALANCE:
            score -= 18; gap_score -= 10; reasons.append("satis tarafi guclu")
        elif imbalance <= 0.85:
            score -= 8; gap_score -= 5; reasons.append("satis tarafi onde")

        if real_bid_wall and bid_wall_dist <= MEXC_OB_BID_WALL_CLOSE_PCT:
            score += 10; reasons.append("yakinda alis duvari")
        if real_ask_wall and ask_wall_dist <= MEXC_OB_ASK_WALL_CLOSE_PCT:
            score -= 16; gap_score -= 12; reasons.append("yakinda satis duvari")
        if liquidity_gap_up:
            score += 10; gap_score += 25; reasons.append("yukari likidite boslugu")
        if liquidity_gap_down:
            score -= 10; gap_score -= 20; reasons.append("asagi likidite boslugu")

        orderbook_block = bool(real_ask_wall and ask_wall_dist <= MEXC_OB_ASK_WALL_BLOCK_PCT and imbalance <= 1.05 and ask_wall_usdt > bid_wall_usdt * 1.2)
        if orderbook_block:
            reasons.append("satis duvari cok yakin")

        score = int(max(0, min(100, round(score))))
        gap_score = int(max(0, min(100, round(gap_score))))
        if orderbook_block:
            status = "SATICI_DUVARI_BLOCK"
        elif score >= 72:
            status = "ALICI USTUN"
        elif score >= 60:
            status = "ALICI AVANTAJLI"
        elif score <= 30:
            status = "SATICI USTUN"
        elif score <= 42:
            status = "SATICI AVANTAJLI"
        else:
            status = "DENGELI"

        out.update({
            "orderbook_ok": True,
            "orderbook_score": score,
            "orderbook_status": status,
            "bid_wall_price": bid_wall_price,
            "bid_wall_usdt": bid_wall_usdt if real_bid_wall else 0.0,
            "bid_wall_distance_pct": bid_wall_dist if real_bid_wall else 999.0,
            "ask_wall_price": ask_wall_price,
            "ask_wall_usdt": ask_wall_usdt if real_ask_wall else 0.0,
            "ask_wall_distance_pct": ask_wall_dist if real_ask_wall else 999.0,
            "bid_usdt_1pct": bid_usdt_1,
            "ask_usdt_1pct": ask_usdt_1,
            "book_imbalance": imbalance,
            "liquidity_gap_up": liquidity_gap_up,
            "liquidity_gap_down": liquidity_gap_down,
            "liquidity_gap_score": gap_score,
            "orderbook_block": orderbook_block,
            "orderbook_reason": ", ".join(reasons[:5]) if reasons else "DENGELI",
        })
        mexc_orderbook_cache[cache_key] = {"time": now, "data": out}
        return out
    except Exception as e:
        print("MEXC order book context hata:", symbol, e, flush=True)
        mexc_orderbook_cache[cache_key] = {"time": now, "data": out}
        return out


def attach_mexc_orderbook_context(symbol, d):
    if not d:
        return d
    price = float(d.get("entry", d.get("price", 0)) or 0)
    ob = fetch_mexc_orderbook_context(symbol, price)
    d.update(ob)
    return d


def attach_mexc_order_flow_package(symbol, d):
    """
    V43 MEXC ORDER FLOW / LIKIDASYON PROXY:
    MEXC'te Binance gibi temiz taker long/short verisi her zaman olmadigi icin sentetik hesap kullanir.
    Para etkisi, hacim gucu, OBV/MACD/EMA, order book ve likidite boslugu birlikte degerlendirilir.
    """
    if not d:
        return d

    money = float(d.get("money_impact", 0) or 0)
    power = float(d.get("volume_power", 0) or 0)
    market = float(d.get("market_impact_pct", 0) or 0)
    flow_score = int(d.get("flow_score", 0) or 0)
    ob_score = int(d.get("orderbook_score", 50) or 50)
    gap_score = int(d.get("liquidity_gap_score", 50) or 50)
    rsi_value = float(d.get("rsi", d.get("rsi15", 0)) or 0)
    module = d.get("module", "UNKNOWN")

    order_flow = 50
    reasons = []
    if money >= 3.0:
        order_flow += 14; reasons.append("para agresif")
    elif money >= 2.0:
        order_flow += 9; reasons.append("para guclu")
    elif money >= 1.4:
        order_flow += 5; reasons.append("para var")

    if power >= 10:
        order_flow += 14; reasons.append("hacim saldirisi")
    elif power >= 5:
        order_flow += 9; reasons.append("hacim guclu")
    elif power >= 2.5:
        order_flow += 5; reasons.append("hacim destekli")

    if flow_score >= FLOW_SCORE_STRONG:
        order_flow += 12; reasons.append("sentetik alici baskisi")
    elif flow_score >= FLOW_SCORE_MIN_FOR_GOLD:
        order_flow += 6; reasons.append("alici baskisi var")
    else:
        order_flow -= 8; reasons.append("alici baskisi zayif")

    if ob_score >= 72:
        order_flow += 10; reasons.append("order book alici")
    elif ob_score <= 42:
        order_flow -= 10; reasons.append("order book satici")

    if gap_score >= MEXC_LIQ_GAP_STRONG:
        order_flow += 8; reasons.append("yukari bosluk")
    elif gap_score <= 35:
        order_flow -= 8; reasons.append("asagi bosluk")

    if d.get("gtu_block") or d.get("live_guard_ok") is False:
        order_flow -= 15; reasons.append("grafik zayif")
    if rsi_value >= 78:
        order_flow -= 10; reasons.append("rsi sisik")

    order_flow = int(max(0, min(100, round(order_flow))))
    if order_flow >= 82:
        of_status = "AGRESIF ALICI"
    elif order_flow >= 68:
        of_status = "ALICI BASKIN"
    elif order_flow <= 30:
        of_status = "AGRESIF SATICI"
    elif order_flow <= 42:
        of_status = "SATICI BASKIN"
    else:
        of_status = "NOTR"

    # Likidasyon proxy: gercek likidasyon haritasi degildir; squeeze ihtimali icin tahmini skor.
    squeeze_score = 50
    squeeze_reasons = []
    if order_flow >= 75:
        squeeze_score += 14; squeeze_reasons.append("alici saldirisi")
    if gap_score >= 75:
        squeeze_score += 14; squeeze_reasons.append("ust bosluk")
    if ob_score >= 68:
        squeeze_score += 8; squeeze_reasons.append("satici duvari zayif")
    if market >= 1.0:
        squeeze_score += 8; squeeze_reasons.append("market etki")
    if module in ("SQUEEZE_EXPLOSION", "ROCKET", "PRE_ROCKET_WATCH"):
        squeeze_score += 8; squeeze_reasons.append("squeeze/rocket mod")
    if d.get("orderbook_block") or gap_score <= 35:
        squeeze_score -= 18; squeeze_reasons.append("duvar/bosluk riski")
    if rsi_value >= 80:
        squeeze_score -= 8; squeeze_reasons.append("rsi cok yuksek")
    squeeze_score = int(max(0, min(100, round(squeeze_score))))

    # Balina supurme: dip/igne radarlarinin kalitesini tek skorda toplar.
    whale_score = 50
    whale_reasons = []
    if float(d.get("lower_wick", 0) or 0) >= 0.35:
        whale_score += 12; whale_reasons.append("alt fitil")
    if float(d.get("recovery_ratio", 0) or 0) >= 0.60:
        whale_score += 12; whale_reasons.append("mum geri aldi")
    if d.get("deep_sweep") or d.get("touched_bb") or d.get("close_back_inside"):
        whale_score += 12; whale_reasons.append("sweep/bb tepki")
    if d.get("obv_up"):
        whale_score += 8; whale_reasons.append("obv toparliyor")
    if money >= 1.5 and power >= 2.5:
        whale_score += 8; whale_reasons.append("tepkide para")
    if d.get("reclaim_ema9") or d.get("reclaim_mid") or d.get("ema_reclaim"):
        whale_score += 6; whale_reasons.append("ema geri alma")
    if module not in ("V_DIP_RECOVERY", "EARLY_REVERSAL", "DIP_REACTION", "DIP", "ELITE_WHALE"):
        whale_score -= 12
    whale_score = int(max(0, min(100, round(whale_score))))

    d["order_flow_score"] = order_flow
    d["order_flow_status"] = of_status
    d["order_flow_reason"] = ", ".join(reasons[:5]) if reasons else "NOTR"
    d["squeeze_proxy_score"] = squeeze_score
    d["squeeze_proxy_status"] = "SHORT SIKISMA ADAYI" if squeeze_score >= MEXC_SQUEEZE_PROXY_STRONG else ("NOTR" if squeeze_score >= 45 else "LONG RISK")
    d["squeeze_proxy_reason"] = ", ".join(squeeze_reasons[:4]) if squeeze_reasons else "NOTR"
    d["whale_sweep_score"] = whale_score
    d["whale_sweep_status"] = "BALINA SUPURME GUCLU" if whale_score >= MEXC_WHALE_SWEEP_STRONG else ("VAR" if whale_score >= 65 else "YOK/NOTR")
    d["whale_sweep_reason"] = ", ".join(whale_reasons[:4]) if whale_reasons else "NOTR"
    d["aggressive_buyer"] = bool(order_flow >= 75)
    d["aggressive_seller"] = bool(order_flow <= 35)
    d["short_squeeze_candidate"] = bool(squeeze_score >= MEXC_SQUEEZE_PROXY_STRONG)
    return d



def attach_mexc_higher_timeframe_trend_context(symbol, d):
    """
    V44 MEXC 1H/4H TREND + YORGUNLUK:
    MEXC ince order book nedeniyle 15m sinyaller cok hizli yanabilir.
    1H/4H yapi zayifsa veya 6s yukselisten sonra tepe donusu basladiysa Elite kapisi sertlesir.
    """
    if not d:
        return d
    try:
        df15 = fetch_df(symbol, "15m", 160)
        df1h = fetch_df(symbol, "1h", 120)
        df4h = fetch_df(symbol, "4h", 80)
        if df15 is None or df1h is None or len(df15) < 30 or len(df1h) < 20:
            d.update({
                "htf_trend_score": 50,
                "htf_trend_status": "HTF VERI YOK",
                "htf_trend_reason": "VERI YOK",
                "fatigue_block": False,
                "fatigue_penalty": 0,
            })
            return d

        m15 = df15.iloc[-1]
        h1 = df1h.iloc[-1]
        h1p = df1h.iloc[-2]
        score = 50
        reasons = []
        if h1.close > h1.ema21:
            score += 12; reasons.append("1H EMA21 ustu")
        else:
            score -= 12; reasons.append("1H EMA21 alti")
        if h1.ema9 >= h1.ema21:
            score += 8; reasons.append("1H EMA pozitif")
        else:
            score -= 6; reasons.append("1H EMA zayif")
        if h1.macd > h1.macd_signal and h1.macd >= h1p.macd:
            score += 10; reasons.append("1H MACD guclu")
        elif h1.macd < h1.macd_signal:
            score -= 8; reasons.append("1H MACD zayif")
        if 42 <= float(h1.rsi) <= 68:
            score += 6; reasons.append("1H RSI saglikli")
        elif float(h1.rsi) >= 74:
            score -= 10; reasons.append("1H RSI sisik")

        if df4h is not None and len(df4h) >= 20:
            h4 = df4h.iloc[-1]
            h4p = df4h.iloc[-2]
            if h4.close > h4.ema21:
                score += 8; reasons.append("4H EMA21 ustu")
            else:
                score -= 6; reasons.append("4H EMA21 alti")
            if h4.macd >= h4p.macd:
                score += 5; reasons.append("4H MACD toparliyor")
            else:
                score -= 4; reasons.append("4H MACD zayif")

        price = float(m15.close)
        p6h = float(df15["close"].iloc[-25]) if len(df15) >= 25 else float(df15["close"].iloc[0])
        high_6h = float(df15["high"].tail(24).max())
        gain_6h = ((price - p6h) / p6h * 100) if p6h > 0 else 0.0
        pullback_from_6h_high = ((high_6h - price) / high_6h * 100) if high_6h > 0 else 0.0
        last_red = bool(df15["close"].iloc[-1] < df15["open"].iloc[-1])
        prev_red = bool(df15["close"].iloc[-2] < df15["open"].iloc[-2])
        macd_hist_now = float(df15["macd"].iloc[-1] - df15["macd_signal"].iloc[-1])
        macd_hist_prev = float(df15["macd"].iloc[-2] - df15["macd_signal"].iloc[-2])
        hist_weak = macd_hist_now < macd_hist_prev
        fatigue_penalty = 0
        fatigue_block = False
        if gain_6h >= MEXC_FATIGUE_6H_GAIN_WARN and (pullback_from_6h_high >= MEXC_FATIGUE_PULLBACK_MIN or (last_red and hist_weak)):
            fatigue_penalty += MEXC_FATIGUE_PENALTY; reasons.append("6s yukselis yorgun")
        if gain_6h >= MEXC_FATIGUE_6H_GAIN_BLOCK and pullback_from_6h_high >= MEXC_FATIGUE_PULLBACK_MIN and (last_red or prev_red or hist_weak):
            fatigue_block = True; reasons.append("tepe sonrasi yorulma")

        score = int(max(0, min(100, round(score - fatigue_penalty))))
        if fatigue_block:
            status = "YORGUNLUK_BLOCK"
        elif score >= 76:
            status = "HTF GUCLU"
        elif score >= 60:
            status = "HTF POZITIF"
        elif score <= 38:
            status = "HTF ZAYIF"
        else:
            status = "HTF NOTR"
        d.update({
            "htf_trend_score": score,
            "htf_trend_status": status,
            "htf_trend_reason": ", ".join(reasons[:6]) if reasons else "NOTR",
            "htf_gain_6h": gain_6h,
            "htf_pullback_from_high": pullback_from_6h_high,
            "fatigue_block": bool(fatigue_block),
            "fatigue_penalty": int(fatigue_penalty),
        })
        return d
    except Exception as e:
        print("MEXC HTF trend context hata:", symbol, e, flush=True)
        d.update({
            "htf_trend_score": 50,
            "htf_trend_status": "HTF HATA",
            "htf_trend_reason": "HATA",
            "fatigue_block": False,
            "fatigue_penalty": 0,
        })
        return d

def sr_elite_gate_ok(d):
    """
    Direncin hemen altinda AL verme korumasi.
    Guclu squeeze/para olsa bile direnÃ§ kirilmadiysa ve mesafe cok darsa Elite kapisi kapanir.
    """
    if not d or not d.get("sr_ok"):
        return True

    module = d.get("module", "UNKNOWN")
    resistance_distance = float(d.get("sr_resistance_distance_pct", 999) or 999)
    support_distance = float(d.get("sr_support_distance_pct", 999) or 999)
    breakout = bool(d.get("sr_breakout"))

    # Dip/V toparlanma sinyallerinde ana fikir destek/dipten tepki oldugu icin direnÃ§ filtresi daha esnek.
    dip_like = module in ("DIP", "DIP_REACTION", "DIP_SWEEP", "ELITE_WHALE", "V_DIP_RECOVERY")
    strong_context = (
        bool(d.get("memory_reentry_bonus"))
        or bool(d.get("second_wave_bonus"))
        or bool(d.get("money_memory_bonus"))
        or bool(d.get("squeeze_fast_pre_elite"))
        or float(d.get("market_impact_pct", 0) or 0) >= 2.0
    )

    if breakout:
        return True

    if dip_like:
        return not (0 <= resistance_distance <= 0.50 and support_distance > 5)

    # Tam direncin altinda ise AL yok; Gold/Hazirlik olarak kalsin.
    if 0 <= resistance_distance <= SR_RESISTANCE_VERY_NEAR_PCT:
        return False

    # DirenÃ§ yakin + destek uzaksa risk/odul zayif.
    if 0 <= resistance_distance <= SR_RESISTANCE_NEAR_PCT and support_distance > SR_SUPPORT_CLOSE_PCT and not strong_context:
        return False

    return True



def v_dip_recovery_signal(symbol, rs):
    """
    V_DIP_RECOVERY / PANIC_SWEEP_RECOVERY:
    H/USDT tipi sert dump + alt supurme + hacimli V donusleri yakalar.
    Normal FOMO degildir; once sert dusus vardir, sonra guclu geri alis vardir.
    """
    df15 = fetch_df(symbol, "15m", 180)
    df1h = fetch_df(symbol, "1h", 120)
    if df15 is None or df1h is None or len(df15) < 50:
        return False, None

    m15 = df15.iloc[-1]
    p1 = df15.iloc[-2]
    p2 = df15.iloc[-3]
    h1 = df1h.iloc[-1]
    h1_prev = df1h.iloc[-2]

    price = m15.close
    recent = df15.tail(24)
    recent_low = recent["low"].min()
    recent_high_before_low = df15["high"].iloc[-32:-3].max() if len(df15) >= 32 else recent["high"].max()
    low_idx = recent["low"].idxmin()

    drop_from_high = ((recent_high_before_low - recent_low) / recent_high_before_low) * 100 if recent_high_before_low > 0 else 0
    recovery_from_low = ((price - recent_low) / recent_low) * 100 if recent_low > 0 else 0
    still_below_high = ((recent_high_before_low - price) / recent_high_before_low) * 100 if recent_high_before_low > 0 else 999
    dist_from_low = recovery_from_low

    candles = [m15, p1, p2]
    lower_wick = max(c.lower_wick for c in candles)
    recovery_ratio = max(c.recovery_ratio for c in candles)

    touched_bb = any(c.low <= c.bb_lower * 1.012 for c in candles)
    deep_sweep = any(c.low < c.bb_lower and c.close > c.bb_lower for c in candles)
    close_back_inside = any(c.close > c.bb_lower for c in candles)

    # V27 FAST LIQUIDITY SWEEP:
    # BSB tipi hareket: aşağı likidasyonu alır, mumun büyük kısmını geri toplar,
    # hacim kıpırdar ve coin Elite olmadan önce çok hızlı kalkabilir.
    fast_liquidity_sweep = (
        lower_wick >= FAST_LIQ_SWEEP_MIN_WICK
        and recovery_ratio >= FAST_LIQ_SWEEP_MIN_RECOVERY
        and recovery_from_low <= FAST_LIQ_SWEEP_MAX_DIST
        and m15.rsi <= FAST_LIQ_SWEEP_MAX_RSI
        and (touched_bb or deep_sweep or close_back_inside)
    )

    reclaim_ema9 = m15.close > m15.ema9 or p1.close > p1.ema9
    reclaim_mid = m15.close > m15.bb_middle or p1.close > p1.bb_middle

    last3_vol = df15["volume"].tail(3).mean()
    prev20_vol = df15["volume"].iloc[-24:-4].mean()
    vol_ratio = last3_vol / prev20_vol if prev20_vol > 0 else 0
    if fast_liquidity_sweep and vol_ratio >= FAST_LIQ_SWEEP_MIN_VOL_RATIO:
        fast_liquidity_sweep = True
    else:
        fast_liquidity_sweep = False

    usdt_vol = df15["volume"].tail(3).sum() * price
    avg_usdt_vol = df15["vol_avg"].tail(3).sum() * price if df15["vol_avg"].tail(3).sum() > 0 else 0
    money_impact = usdt_vol / avg_usdt_vol if avg_usdt_vol > 0 else 0
    volume_power = money_impact * vol_ratio

    rsi_turn = m15.rsi > p1.rsi or p1.rsi > p2.rsi
    macd_turn = m15.macd > df15["macd"].iloc[-4] or h1.macd > h1_prev.macd
    obv_recover = df15["obv"].iloc[-1] > df15["obv"].iloc[-5]
    green_reaction = (m15.close > m15.open) or (p1.close > p1.open)

    # Bu radar tam panik-dip toparlanmasi icin. Ufak yatay tepkiyi alma.
    if drop_from_high < 10:
        return False, None
    if recovery_from_low < 6 and lower_wick < FAST_LIQ_SWEEP_MIN_WICK:
        return False, None
    if recovery_from_low > 55:
        return False, None
    if still_below_high < 12:
        return False, None
    if m15.rsi > 68:
        return False, None

    score = 0
    reasons = []
    if drop_from_high >= 25:
        score += 5; reasons.append("Sert dump sonrasi")
    elif drop_from_high >= 15:
        score += 4; reasons.append("Dump sonrasi tepki")
    if recovery_from_low >= 15:
        score += 5; reasons.append("Dipten guclu V toparlanma")
    elif recovery_from_low >= 8:
        score += 3; reasons.append("Dipten V toparlanma")
    if still_below_high >= 20:
        score += 3; reasons.append("Eski tepeye hala uzak")
    if lower_wick >= 0.55:
        score += 4; reasons.append("Alt supurme fitili")
    elif lower_wick >= 0.35:
        score += 2; reasons.append("Alt fitil")
    if recovery_ratio >= 0.70:
        score += 3; reasons.append("Mum dipten geri aldi")
    if touched_bb:
        score += 3; reasons.append("Alt Bollinger bolgesi")
    if deep_sweep:
        score += 4; reasons.append("Bollinger disi supurme")
    if close_back_inside:
        score += 2; reasons.append("Bant icine geri donus")
    if fast_liquidity_sweep:
        score += 8; reasons.append("FAST LIQUIDITY SWEEP")
    if reclaim_ema9:
        score += 2; reasons.append("EMA9 geri alma")
    if reclaim_mid:
        score += 2; reasons.append("BB orta geri alma")
    if vol_ratio >= 2.0:
        score += 4; reasons.append("Tepkide hacim patlamasi")
    elif vol_ratio >= 1.35:
        score += 2; reasons.append("Tepkide hacim artisi")
    if money_impact >= 2.0:
        score += 4; reasons.append("Para etkisi guclu")
    elif money_impact >= 1.25:
        score += 2; reasons.append("Para etkisi var")
    if volume_power >= 5.0:
        score += 4; reasons.append("Hacim gucu cok guclu")
    elif volume_power >= 2.5:
        score += 2; reasons.append("Hacim gucu var")
    if rsi_turn:
        score += 2; reasons.append("RSI dipten donuyor")
    if macd_turn:
        score += 2; reasons.append("MACD toparlaniyor")
    if obv_recover:
        score += 3; reasons.append("OBV toparlaniyor")
    if green_reaction:
        score += 1; reasons.append("Yesil tepki mumu")
    if rs >= 45:
        score += 1; reasons.append("RS yeterli")

    normal_v_dip_valid = (
        score >= 20
        and drop_from_high >= 12
        and 6 <= recovery_from_low <= 45
        and still_below_high >= 12
        and vol_ratio >= 1.25
        and money_impact >= 1.15
        and volume_power >= 1.8
        and m15.rsi <= 66
        and (lower_wick >= 0.35 or touched_bb or deep_sweep)
        and (rsi_turn or macd_turn or obv_recover or reclaim_ema9)
    )

    fast_sweep_valid = (
        fast_liquidity_sweep
        and score >= 18
        and vol_ratio >= FAST_LIQ_SWEEP_MIN_VOL_RATIO
        and money_impact >= 1.05
        and volume_power >= 1.20
        and m15.rsi <= FAST_LIQ_SWEEP_MAX_RSI
        and (rsi_turn or macd_turn or obv_recover or green_reaction or reclaim_ema9)
    )

    valid = normal_v_dip_valid or fast_sweep_valid

    return valid, {
        "module": "V_DIP_RECOVERY",
        "score": score,
        "priority": 46,
        "price": price,
        "rs": rs,
        "vol_ratio": vol_ratio,
        "usdt_vol": usdt_vol,
        "money_impact": money_impact,
        "volume_power": volume_power,
        "rsi": m15.rsi,
        "dist_from_low": dist_from_low,
        "drop_from_high": drop_from_high,
        "recovery_from_low": recovery_from_low,
        "still_below_high": still_below_high,
        "lower_wick": lower_wick,
        "recovery_ratio": recovery_ratio,
        "touched_bb": touched_bb,
        "deep_sweep": deep_sweep,
        "close_back_inside": close_back_inside,
        "fast_liquidity_sweep": fast_liquidity_sweep,
        "reclaim_ema9": reclaim_ema9,
        "reclaim_mid": reclaim_mid,
        "rsi_turn": rsi_turn,
        "macd_turn": macd_turn,
        "obv_up": obv_recover,
        "green_reaction": green_reaction,
        "price_gain_15m": 0,
        "price_gain_30m": 0,
        "fomo_exempt": True,
        "reasons": reasons,
    }

def trend_buildup_signal(symbol, rs):
    """
    TREND_BUILDUP / SESSIZ YUKSELIS RADARI:
    VELVET tipi tek mum patlamasi olmadan, parca parca yukselen ve alici akisi devam eden coinleri yakalar.
    Amac 0.36 -> 0.59 olduktan sonra degil; 0.36 -> 0.40/0.42 araliginda fark etmek.
    """
    df15 = fetch_df(symbol, "15m", 180)
    df1h = fetch_df(symbol, "1h", 160)
    if df15 is None or df1h is None or len(df15) < 60 or len(df1h) < 30:
        return False, None

    m15 = df15.iloc[-1]
    h1 = df1h.iloc[-1]
    h1_prev = df1h.iloc[-2]

    price = m15.close
    p6h = df15["close"].iloc[-25]
    p12h = df15["close"].iloc[-49] if len(df15) >= 49 else df15["close"].iloc[0]
    price_change_6h = ((price - p6h) / p6h) * 100 if p6h > 0 else 0
    price_change_12h = ((price - p12h) / p12h) * 100 if p12h > 0 else 0

    low_24h = df15["low"].tail(96).min()
    high_24h = df15["high"].tail(96).max()
    dist_from_low = ((price - low_24h) / low_24h) * 100 if low_24h > 0 else 999
    pullback_from_high = ((high_24h - price) / high_24h) * 100 if high_24h > 0 else 999

    lows = df15["low"].tail(24).reset_index(drop=True)
    highs = df15["high"].tail(24).reset_index(drop=True)
    closes = df15["close"].tail(24).reset_index(drop=True)

    higher_low_count = 0
    higher_high_count = 0
    for i in range(4, len(lows), 4):
        if lows.iloc[i] > lows.iloc[i-4]:
            higher_low_count += 1
        if highs.iloc[i] > highs.iloc[i-4]:
            higher_high_count += 1

    green_count = int((df15["close"].tail(12) > df15["open"].tail(12)).sum())
    close_above_ema9_count = int((df15["close"].tail(12) > df15["ema9"].tail(12)).sum())
    close_above_ema21_count = int((df15["close"].tail(12) > df15["ema21"].tail(12)).sum())

    last8_vol = df15["volume"].tail(8).mean()
    prev16_vol = df15["volume"].iloc[-24:-8].mean()
    vol_ratio = last8_vol / prev16_vol if prev16_vol > 0 else 0

    usdt_vol = df15["volume"].tail(8).sum() * price
    avg_usdt_vol = df15["vol_avg"].tail(8).sum() * price if df15["vol_avg"].tail(8).sum() > 0 else 0
    money_impact = usdt_vol / avg_usdt_vol if avg_usdt_vol > 0 else 0
    volume_power = money_impact * vol_ratio

    obv_up = df15["obv"].iloc[-1] > df15["obv"].iloc[-16]
    macd_turn = m15.macd > df15["macd"].iloc[-4]
    h1_macd_turn = h1.macd > h1_prev.macd
    ema_structure = m15.close > m15.ema21 and m15.ema9 >= m15.ema21 * 0.995
    h1_structure = h1.close > h1.ema21 or h1.ema9 >= h1.ema21 * 0.995
    bb_not_expanded_too_much = m15.bb_width <= 0.16

    # Coktan ucup gitmis veya tamamen dusus trendinde olanlari alma.
    if price_change_6h > 22 or price_change_12h > 38:
        return False, None
    if price_change_6h < 1.2:
        return False, None
    if m15.rsi > 74 or m15.rsi < 45:
        return False, None
    if dist_from_low > 28:
        return False, None

    score = 0
    reasons = []
    if higher_low_count >= 3:
        score += 3; reasons.append("Higher Low yapisi")
    elif higher_low_count >= 2:
        score += 2; reasons.append("Higher Low basliyor")
    if higher_high_count >= 2:
        score += 2; reasons.append("Higher High basliyor")
    if close_above_ema9_count >= 7:
        score += 2; reasons.append("15m EMA9 ustu tutunma")
    if close_above_ema21_count >= 8:
        score += 2; reasons.append("15m EMA21 ustu tutunma")
    if ema_structure:
        score += 2; reasons.append("EMA yapi yukari donuyor")
    if h1_structure:
        score += 2; reasons.append("1H yapi toparliyor")
    if 50 <= m15.rsi <= 68:
        score += 2; reasons.append("RSI trend bolgesi")
    elif 45 <= m15.rsi <= 72:
        score += 1; reasons.append("RSI uygun")
    if 1.2 <= vol_ratio <= 3.5:
        score += 2; reasons.append("Hacim sessiz artiyor")
    if money_impact >= 1.25:
        score += 2; reasons.append("Para etkisi surekli pozitif")
    if volume_power >= 2.0:
        score += 2; reasons.append("Hacim gucu birikiyor")
    if obv_up:
        score += 3; reasons.append("OBV birikim yapiyor")
    if macd_turn or h1_macd_turn:
        score += 2; reasons.append("MACD toparlaniyor")
    if 2.0 <= price_change_6h <= 14:
        score += 3; reasons.append("6s kontrollu yukselis")
    elif 1.2 <= price_change_6h <= 18:
        score += 1; reasons.append("6s yukselis var")
    if pullback_from_high <= 8:
        score += 1; reasons.append("Tepeye yakin tutunuyor")
    if bb_not_expanded_too_much:
        score += 1; reasons.append("FOMO BB genislemesi yok")
    if rs >= 55:
        score += 1; reasons.append("RS yeterli")

    valid = (
        score >= 16
        and higher_low_count >= 2
        and close_above_ema21_count >= 7
        and ema_structure
        and h1_structure
        and 1.2 <= price_change_6h <= 18
        and price_change_12h <= 35
        and 45 <= m15.rsi <= 72
        and vol_ratio >= 1.15
        and money_impact >= 1.15
        and volume_power >= 1.6
        and (obv_up or macd_turn or h1_macd_turn)
    )

    return valid, {
        "module": "TREND_BUILDUP",
        "score": score,
        "priority": 34,
        "price": price,
        "rs": rs,
        "vol_ratio": vol_ratio,
        "usdt_vol": usdt_vol,
        "money_impact": money_impact,
        "volume_power": volume_power,
        "rsi": m15.rsi,
        "dist_from_low": dist_from_low,
        "price_change_6h": price_change_6h,
        "price_change_12h": price_change_12h,
        "pullback_from_high": pullback_from_high,
        "higher_low_count": higher_low_count,
        "higher_high_count": higher_high_count,
        "close_above_ema9_count": close_above_ema9_count,
        "close_above_ema21_count": close_above_ema21_count,
        "green_count": green_count,
        "obv_up": obv_up,
        "macd_turn": macd_turn or h1_macd_turn,
        "ema_structure": ema_structure,
        "h1_structure": h1_structure,
        "bb_width": m15.bb_width,
        "reasons": reasons,
    }



def soft_wakeup_signal(symbol, rs):
    """
    WAKEUP / UYANIS HAFIZASI:
    Radar mesaji atmak icin degil, radar hafizasini erken baslatmak icin kullanilir.
    ROAM / ASTEROID gibi coinler once hafif hacim + OBV + MA20 toparlanma gosterir,
    klasik radarlar ise henuz yanmayabilir. Bu fonksiyon o ilk izi kaydeder.
    """
    df15 = fetch_df(symbol, "15m", 120)
    df1h = fetch_df(symbol, "1h", 80)
    if df15 is None or df1h is None or len(df15) < 40:
        return False, None

    m15 = df15.iloc[-1]
    h1 = df1h.iloc[-1]
    price = m15.close

    last4_vol = df15["volume"].tail(4).mean()
    prev16_vol = df15["volume"].iloc[-20:-4].mean()
    vol_ratio = last4_vol / prev16_vol if prev16_vol > 0 else 0

    usdt_vol = df15["volume"].tail(4).sum() * price
    avg_usdt_vol = df15["vol_avg"].tail(4).sum() * price if df15["vol_avg"].tail(4).sum() > 0 else 0
    money_impact = usdt_vol / avg_usdt_vol if avg_usdt_vol > 0 else 0
    volume_power = money_impact * vol_ratio

    obv_up = df15["obv"].iloc[-1] > df15["obv"].iloc[-10]
    macd_turn = m15.macd > df15["macd"].iloc[-4]
    reclaim_ema21 = m15.close > m15.ema21
    h1_reclaim = h1.close > h1.ema21 or h1.ema9 >= h1.ema21 * 0.995

    p2h = df15["close"].iloc[-9]
    price_change_2h = ((price - p2h) / p2h) * 100 if p2h > 0 else 0
    low_24h = df15["low"].tail(96).min()
    dist_from_low = ((price - low_24h) / low_24h) * 100 if low_24h > 0 else 999

    score = 0
    reasons = []
    if vol_ratio >= 1.15:
        score += 2; reasons.append("Hacim uyanmaya basladi")
    if money_impact >= 1.10:
        score += 2; reasons.append("Para etkisi basliyor")
    if volume_power >= 1.40:
        score += 2; reasons.append("Hacim gucu erken")
    if obv_up:
        score += 3; reasons.append("OBV birikim basladi")
    if macd_turn:
        score += 2; reasons.append("MACD toparlaniyor")
    if reclaim_ema21:
        score += 2; reasons.append("15m EMA21 geri alindi")
    if h1_reclaim:
        score += 1; reasons.append("1H yapi toparliyor")
    if 0.3 <= price_change_2h <= 8:
        score += 2; reasons.append("2s kontrollu hareket")
    if 42 <= m15.rsi <= 72:
        score += 1; reasons.append("RSI uygun")
    if rs >= 40:
        score += 1; reasons.append("RS yeterli")

    valid = (
        score >= 8
        and vol_ratio >= 1.10
        and money_impact >= 1.05
        and volume_power >= 1.20
        and 40 <= m15.rsi <= 74
        and price_change_2h <= 10
        and dist_from_low <= 35
        and (obv_up or macd_turn or reclaim_ema21)
    )

    return valid, {
        "module": "WAKEUP",
        "score": score,
        "priority": 5,
        "price": price,
        "rs": rs,
        "vol_ratio": vol_ratio,
        "usdt_vol": usdt_vol,
        "money_impact": money_impact,
        "volume_power": volume_power,
        "rsi": m15.rsi,
        "dist_from_low": dist_from_low,
        "price_change_2h": price_change_2h,
        "obv_up": obv_up,
        "macd_turn": macd_turn,
        "reclaim_ema21": reclaim_ema21,
        "reasons": reasons,
    }





def pre_breakout_watch_signal(symbol, rs):
    """
    V52 PRE BREAKOUT WATCH / ERKEN KIRILIM:
    NFP tipi dipten sonra BB orta bant/EMA geri alinirken, hacim patlamadan once uyarir.
    AL degildir; ana kanal erken takip mesajidir.
    """
    df15 = fetch_df(symbol, "15m", 140)
    df1h = fetch_df(symbol, "1h", 100)
    if df15 is None or df1h is None or len(df15) < 60:
        return False, None

    m15 = df15.iloc[-1]
    p15 = df15.iloc[-2]
    h1 = df1h.iloc[-1]
    h1_prev = df1h.iloc[-2]
    price = float(m15.close)

    low_24h = df15["low"].tail(96).min()
    high_24h = df15["high"].tail(96).max()
    dist_from_low = ((price - low_24h) / low_24h * 100) if low_24h > 0 else 999
    pullback_from_high = ((high_24h - price) / high_24h * 100) if high_24h > 0 else 999
    gains = recent_price_gains(df15, price)
    price_gain_15m = gains.get("price_gain_15m", 0)
    price_gain_30m = gains.get("price_gain_30m", 0)

    vol_ratio_15m = (m15.volume / m15.vol_avg) if m15.vol_avg > 0 else 0
    last4_vol = df15["volume"].tail(4).mean()
    prev12_vol = df15["volume"].iloc[-16:-4].mean()
    vol_ratio = (last4_vol / prev12_vol) if prev12_vol > 0 else vol_ratio_15m
    usdt_vol = df15["volume"].tail(4).sum() * price
    avg_usdt = df15["vol_avg"].tail(4).sum() * price if df15["vol_avg"].tail(4).sum() > 0 else 0
    money_impact = (usdt_vol / avg_usdt) if avg_usdt > 0 else 0
    volume_power = money_impact * max(vol_ratio, vol_ratio_15m)

    ema_reclaim = (m15.close > m15.ema21 and p15.close <= p15.ema21) or (m15.close > m15.ema9 and m15.ema9 >= m15.ema21 * 0.985)
    bb_mid_reclaim = m15.close > m15.bb_middle and p15.close <= p15.bb_middle
    macd_improving = m15.macd > df15["macd"].iloc[-4] or h1.macd > h1_prev.macd
    macd_cross_near = m15.macd > m15.macd_signal or abs(m15.macd - m15.macd_signal) <= max(abs(m15.macd), 1e-12) * 0.60
    obv_turn = df15["obv"].iloc[-1] > df15["obv"].iloc[-8]
    bb_ready = m15.bb_width <= df15["bb_width"].tail(40).quantile(0.70) or m15.bb_width < 0.11
    green_body = m15.close > m15.open and m15.body_ratio >= 0.38

    if not (42 <= m15.rsi <= 70):
        return False, None
    if price_gain_15m > 6.0 or price_gain_30m > 10.5:
        return False, None
    if dist_from_low > 24 or pullback_from_high < 1.0:
        return False, None

    score = 0
    reasons = []
    if rs >= 70:
        score += 2; reasons.append("RS guclu")
    if ema_reclaim:
        score += 3; reasons.append("EMA geri aliniyor")
    if bb_mid_reclaim:
        score += 3; reasons.append("BB orta bant geri alindi")
    if macd_improving:
        score += 2; reasons.append("MACD erken toparlaniyor")
    if macd_cross_near:
        score += 1; reasons.append("MACD kesisime yakin")
    if obv_turn:
        score += 2; reasons.append("OBV donus basladi")
    if vol_ratio >= 1.15 or vol_ratio_15m >= 1.20:
        score += 2; reasons.append("Hacim uyanmaya basladi")
    if money_impact >= 1.10:
        score += 2; reasons.append("Para etkisi erken pozitif")
    if bb_ready:
        score += 1; reasons.append("Bollinger henuz cok genislememis")
    if green_body:
        score += 1; reasons.append("Yesil kirilim mumu")
    if 2 <= dist_from_low <= 18:
        score += 1; reasons.append("Dipten kopus erken bolge")

    valid = score >= 10 and (ema_reclaim or bb_mid_reclaim) and macd_improving and (obv_turn or money_impact >= 1.20 or vol_ratio >= 1.35)
    if not valid:
        return False, None

    return True, {
        "module": "PRE_BREAKOUT_WATCH",
        "priority": 29,
        "score": score,
        "rs": rs,
        "price": price,
        "vol_ratio": max(vol_ratio, vol_ratio_15m),
        "usdt_vol": usdt_vol,
        "money_impact": money_impact,
        "volume_power": volume_power,
        "rsi": m15.rsi,
        "dist_from_low": dist_from_low,
        "pullback_from_high": pullback_from_high,
        "price_gain_15m": price_gain_15m,
        "price_gain_30m": price_gain_30m,
        "ema_reclaim": ema_reclaim,
        "bb_mid_reclaim": bb_mid_reclaim,
        "macd_turn": macd_improving,
        "macd_cross_near": macd_cross_near,
        "obv_up": obv_turn,
        "bb_width": m15.bb_width,
        "bb_ready": bb_ready,
        "reasons": reasons,
    }

def early_reversal_signal(symbol, rs):
    """
    V25 EARLY_REVERSAL:
    ALGO tipi dipten ilk dönüşleri yakalar.
    Tek başına AL değildir; radar hafızasına erken iz bırakır.
    Amaç: MACD tam kesmeden önce RSI/OBV/hacim toparlanmasını görmek.
    """
    df15 = fetch_df(symbol, "15m", 140)
    df1h = fetch_df(symbol, "1h", 120)
    if df15 is None or df1h is None or len(df15) < 50:
        return False, None

    m15 = df15.iloc[-1]
    p1 = df15.iloc[-2]
    p2 = df15.iloc[-3]
    h1 = df1h.iloc[-1]
    h1_prev = df1h.iloc[-2]
    price = m15.close

    recent_low = df15["low"].tail(32).min()
    recent_high = df15["high"].tail(32).max()
    dist_from_low = ((price - recent_low) / recent_low) * 100 if recent_low > 0 else 999
    pullback_from_high = ((recent_high - price) / recent_high) * 100 if recent_high > 0 else 999

    vol_ratio = df15["volume"].tail(3).mean() / df15["volume"].iloc[-24:-4].mean() if df15["volume"].iloc[-24:-4].mean() > 0 else 0
    usdt_vol = df15["volume"].tail(3).sum() * price
    avg_usdt_vol = df15["vol_avg"].tail(3).sum() * price if df15["vol_avg"].tail(3).sum() > 0 else 0
    money_impact = usdt_vol / avg_usdt_vol if avg_usdt_vol > 0 else 0
    volume_power = money_impact * vol_ratio

    rsi_jump = m15.rsi - p1.rsi
    rsi_recover_3 = m15.rsi - p2.rsi
    rsi_turn = rsi_jump >= 3.0 or rsi_recover_3 >= 5.0
    obv_recover = df15["obv"].iloc[-1] > df15["obv"].iloc[-5]
    macd_recover = m15.macd > p1.macd or h1.macd > h1_prev.macd
    hist_now = m15.macd - m15.macd_signal
    hist_prev = p1.macd - p1.macd_signal
    macd_hist_recover = hist_now > hist_prev

    lower_wick = max(m15.lower_wick, p1.lower_wick, p2.lower_wick)
    recovery_ratio = max(m15.recovery_ratio, p1.recovery_ratio, p2.recovery_ratio)
    touched_lower_bb = any(c.low <= c.bb_lower * 1.02 for c in [m15, p1, p2])
    reclaim_ema9 = m15.close > m15.ema9 or p1.close > p1.ema9
    reclaim_ema21 = m15.close > m15.ema21
    reclaim_bb_mid = m15.close > m15.bb_middle
    green_reaction = m15.close > m15.open or p1.close > p1.open

    gains = recent_price_gains(df15, price)
    price_gain_15m = gains["price_gain_15m"]
    price_gain_30m = gains["price_gain_30m"]

    # Bu radar dipten ilk dönüş içindir; çoktan kaçan veya zaten trend üstünde olan coinleri alma.
    if dist_from_low > 14:
        return False, None
    if price_gain_15m > 7 or price_gain_30m > 12:
        return False, None
    if m15.rsi > 68:
        return False, None

    score = 0
    reasons = []
    if dist_from_low <= 6:
        score += 4; reasons.append("Dibe yakin ilk donus")
    elif dist_from_low <= 10:
        score += 2; reasons.append("Dip bolgesinden toparlanma")
    if touched_lower_bb:
        score += 3; reasons.append("Alt Bollinger bolgesinden tepki")
    if lower_wick >= 0.35:
        score += 2; reasons.append("Alt fitil tepki")
    if recovery_ratio >= 0.60:
        score += 2; reasons.append("Mum dipten toparladi")
    if vol_ratio >= 1.30:
        score += 2; reasons.append("Tepkide hacim artisi")
    if money_impact >= 1.15:
        score += 2; reasons.append("Para etkisi basliyor")
    if volume_power >= 1.80:
        score += 2; reasons.append("Hacim gucu erken")
    if rsi_turn:
        score += 3; reasons.append("RSI dipten sert donuyor")
    if obv_recover:
        score += 3; reasons.append("OBV dipten toparliyor")
    if macd_recover or macd_hist_recover:
        score += 2; reasons.append("MACD histogram toparlaniyor")
    if reclaim_ema9:
        score += 2; reasons.append("EMA9 geri alindi")
    if reclaim_ema21:
        score += 1; reasons.append("EMA21 test/geri alma")
    if reclaim_bb_mid:
        score += 1; reasons.append("BB orta banda donus")
    if green_reaction:
        score += 1; reasons.append("Yesil tepki mumu")
    if rs >= 45:
        score += 1; reasons.append("RS yeterli")

    valid = (
        score >= 15
        and dist_from_low <= 12
        and 32 <= m15.rsi <= 68
        and vol_ratio >= 1.15
        and money_impact >= 1.05
        and volume_power >= 1.25
        and (rsi_turn or obv_recover)
        and (macd_recover or macd_hist_recover or reclaim_ema9)
        and (touched_lower_bb or lower_wick >= 0.30 or recovery_ratio >= 0.60)
    )

    return valid, {
        "module": "EARLY_REVERSAL",
        "score": score,
        "priority": 31,
        "price": price,
        "rs": rs,
        "vol_ratio": vol_ratio,
        "usdt_vol": usdt_vol,
        "money_impact": money_impact,
        "volume_power": volume_power,
        "rsi": m15.rsi,
        "rsi_jump": rsi_jump,
        "dist_from_low": dist_from_low,
        "pullback_from_high": pullback_from_high,
        "lower_wick": lower_wick,
        "recovery_ratio": recovery_ratio,
        "touched_lower_bb": touched_lower_bb,
        "reclaim_ema9": reclaim_ema9,
        "reclaim_ema21": reclaim_ema21,
        "reclaim_bb_mid": reclaim_bb_mid,
        "obv_up": obv_recover,
        "macd_turn": macd_recover or macd_hist_recover,
        "green_reaction": green_reaction,
        "price_gain_15m": price_gain_15m,
        "price_gain_30m": price_gain_30m,
        "fomo_exempt": True,
        "reasons": reasons,
    }

