    bb_now = m15.bb_width
    bb_prev_min = df15["bb_width"].iloc[-34:-4].min()
    bb_was_squeezed = bb_prev_min <= 0.08 or box_range_pct <= 8
    bb_expanding = bb_now > df15["bb_width"].iloc[-4]

    range_break = price > box_high_prev * 1.003
