def safe_long(symbol, rs, btc_ok, funding):
    df1m = fetch_df(symbol, "1m", 90)
    df5 = fetch_df(symbol, "5m", 100)
    df15 = fetch_df(symbol, "15m", 150)
    if df1m is None or df5 is None or df15 is None:
        return False, None
    m1 = df1m.iloc[-1]
    prev3 = df1m.iloc[-4]
    m5 = df5.iloc[-1]
    t15 = df15.iloc[-1]
    t15_prev = df15.iloc[-2]
    fib = fib_targets(df15)
    if not fib:
        return False, None
    resistance = fib["high"]
    breakout = m5.close > resistance
    strong_breakout = breakout and m5.body_ratio >= 0.38 and m5.upper_wick <= 0.55
    vol_ratio = m1.volume / m1.vol_avg if m1.vol_avg > 0 else 0
    usdt_vol = m1.volume * m1.close
    avg_usdt_vol = m1.vol_avg * m1.close if m1.vol_avg > 0 else 0
    money_impact = usdt_vol / avg_usdt_vol if avg_usdt_vol > 0 else 0
    volume_power = money_impact * vol_ratio
    change_3m = ((m1.close - prev3.open) / prev3.open) * 100 if prev3.open > 0 else 0
    gains = recent_price_gains(df15, m1.close)
    price_gain_15m = gains["price_gain_15m"]
    price_gain_30m = gains["price_gain_30m"]
    recent_low_15 = df15["low"].tail(32).min()
    dist_from_low = ((m1.close - recent_low_15) / recent_low_15) * 100 if recent_low_15 > 0 else 999
    trend_up = t15.ema9 > t15.ema21
    macd_bull = t15.macd > t15.macd_signal and t15.macd > t15_prev.macd
    low_24h = df15["low"].tail(96).min()
    dist_from_low = ((m1.close - low_24h) / low_24h) * 100 if low_24h > 0 else 999
    score = 0
    if rs >= 65: score += 12
    if vol_ratio >= 2.0: score += 15
    if usdt_vol >= 5000: score += 10
    if money_impact >= 1.2: score += 8
    if volume_power >= 1.60: score += 8
    if change_3m >= 0.20: score += 10
    if trend_up: score += 10
    if macd_bull: score += 10
    if 46 <= t15.rsi <= 80: score += 8
    if strong_breakout: score += 15
    if btc_ok: score += 5
    else: score -= 3
    if funding["ok"]: score += 5
    else: score -= 5
    confidence = max(0, min(100, score))
    valid = confidence >= MIN_SAFE_CONFIDENCE and vol_ratio >= 2.0 and usdt_vol >= 30000 and money_impact >= 1.2 and volume_power >= 2.8 and change_3m >= 0.20 and trend_up and macd_bull and dist_from_low <= 14 and price_gain_15m <= 8 and price_gain_30m <= 15 and t15.rsi <= 76 and (strong_breakout or volume_power >= 3.5 or change_3m >= 0.45)
    price = m1.close
    stop = max(resistance * 0.990, price * 0.970)
    risk = price - stop
    if risk <= 0:
        return False, None
    risk_pct = (risk / price) * 100
    if risk_pct > MAX_RISK_PCT:
        return False, None
    return valid, {"module":"SAFE","score":confidence,"priority":40,"price":price,"confidence":confidence,"rs":rs,"vol_ratio":vol_ratio,"usdt_vol":usdt_vol,"money_impact":money_impact,"volume_power":volume_power,"change_3m":change_3m,"price_gain_15m":price_gain_15m,"price_gain_30m":price_gain_30m,"rsi":t15.rsi,"rsi15":t15.rsi,"dist_from_low":dist_from_low,"trend_up":trend_up,"macd_bull":macd_bull,"breakout":breakout,"strong_breakout":strong_breakout,"entry":price,"stop":stop,"tp1":price+risk*1.5,"tp2":price+risk*2.0,"tp3":price+risk*3.0,"risk_pct":risk_pct,"dist_from_low":dist_from_low,"reasons":["Trend yukari","MACD yukari","Momentum onayi"]}


