def send_mexc_elite_signal(symbol, best, support, btc_status=""):
    if not MEXC_ELITE_GOLD_CHAT_ID:
        return False

    # V26: Elite kapısından hemen önce canlı momentum/red flag kontrolü.
    # MEXC'te Delta yok; bu kontrol ALLO tipi sönen hareketleri azaltmak için kullanılır.
    attach_live_momentum_guard(symbol, best)

    # V37: Elite kapısından hemen önce destek/direnç konumunu hesapla.
    attach_support_resistance_context(symbol, best)

    # V41: Teknik sinyal ile grafik görüntüsü uyumlu mu kontrol et.
    attach_graph_technical_alignment_mexc(symbol, best)

    # V44: 1H / 4H trend ve yukselis yorgunlugu kontrolu.
    attach_mexc_higher_timeframe_trend_context(symbol, best)

    # V43: Order book / order flow / likidite boslugu / squeeze proxy paketini ekle.
    attach_mexc_orderbook_context(symbol, best)
    attach_mexc_order_flow_package(symbol, best)

    # V46: AI karar katmani - radar agirligi + sira + canli kalite guveni.
    attach_mexc_elite_confidence(best, support)

    elite_score = mexc_elite_score_signal(best, support, btc_status)

    if best.get("live_guard_ok") is False:
        print("MEXC LIVE GUARD RED:", symbol, best.get("module"), best.get("live_guard_reason"), "Flags:", best.get("live_red_flags"), flush=True)
        return False

    if best.get("gtu_block"):
        print("MEXC GTU BLOCK:", symbol, best.get("module"), best.get("gtu_status"), best.get("gtu_reasons"), flush=True)
        return False

    if best.get("orderbook_block"):
        print("MEXC ORDERBOOK BLOCK:", symbol, best.get("module"), best.get("orderbook_status"), best.get("orderbook_reason"), flush=True)
        return False

    if int(best.get("elite_confidence_score", 50) or 50) < MEXC_ELITE_CONFIDENCE_BLOCK_SCORE and best.get("module") not in ("DIP", "DIP_REACTION", "DIP_SWEEP", "V_DIP_RECOVERY", "ELITE_WHALE"):
        print("MEXC ELITE CONFIDENCE BLOCK:", symbol, best.get("module"), best.get("elite_confidence_score"), best.get("elite_confidence_reason"), flush=True)
        return False

    # V44: Order flow / HTF / cok yakin direnc sert bloklari.
    if best.get("aggressive_seller") or int(best.get("order_flow_score", 50) or 50) <= MEXC_ORDER_FLOW_BLOCK_SCORE:
        print("MEXC ORDER FLOW BLOCK:", symbol, best.get("module"), best.get("order_flow_status"), best.get("order_flow_reason"), flush=True)
        return False
    if best.get("fatigue_block"):
        print("MEXC FATIGUE BLOCK:", symbol, best.get("module"), best.get("htf_trend_status"), best.get("htf_trend_reason"), flush=True)
        return False
    if int(best.get("htf_trend_score", 50) or 50) < MEXC_HTF_TREND_MIN_FOR_ELITE and best.get("module") not in ("DIP", "DIP_REACTION", "V_DIP_RECOVERY", "ELITE_WHALE"):
        print("MEXC HTF TREND LOW:", symbol, best.get("module"), best.get("htf_trend_score"), flush=True)
        return False
    if (
        best.get("sr_ok")
        and not best.get("sr_breakout")
        and 0 <= float(best.get("sr_resistance_distance_pct", 999) or 999) <= MEXC_HARD_RESISTANCE_BLOCK_PCT
        and not best.get("short_squeeze_candidate")
    ):
        print("MEXC HARD RESISTANCE BLOCK:", symbol, best.get("module"), best.get("sr_resistance_distance_pct"), flush=True)
        return False

    if not mexc_elite_allowed(best, support, btc_status):
        print("MEXC ELITE RED:", symbol, best.get("module"), "BTC:", btc_status, "EliteScore:", elite_score, "Support:", support, flush=True)
        return False

    print("MEXC ELITE CHECK:", symbol, best.get("module"), "EliteScore:", elite_score, "Min:", MEXC_ELITE_MIN_SCORE, "Support:", support, flush=True)

    key = symbol + "_MEXC_ELITE_" + best.get("module", "UNKNOWN")
    if not can_send(sent_mexc_elite, key, MEXC_ELITE_COOLDOWN):
        return False

    pie_record_elite_signal(symbol, best, support, elite_score, pie_build_mexc_levels(best), market="MEXC")

    # V51: MEXC iki kanalli yapi. Eski Elite AL kanali kaldirildi.
    # Elite kapisini gecen tum final AL/Gold mesajlari MEXC_ELITE_GOLD_CHAT_ID kanalina gider.
    elite_gold = mexc_elite_gold_signal(best, support)
    target_chat_id = MEXC_ELITE_GOLD_CHAT_ID
    send_telegram(format_mexc_elite_signal(symbol, best, elite_score, support), target_chat_id)
    print("MEXC GOLD SEND:", symbol, best.get("module"), "Gold:" if elite_gold else "DikkatliGold:", target_chat_id, "EliteScore:", elite_score, flush=True)
    return True


def signal_price_gain_pct(d):
    """Sinyal fiyatinin ilk takip fiyatindan veya son dibinden ne kadar uzaklastigini olcer."""
    if not d:
        return 999
    if "price_gain_from_first" in d:
        return d.get("price_gain_from_first", 999)
    dist = d.get("dist_from_low", None)
    if dist is not None:
        return dist
    return 999


def radar_support_score(module, support_modules):
    support_modules = support_modules or []
    s = set(support_modules)
    score = 0

    # Erken yakalayan radarlar en degerli.
    # V28: modül baz puani. Geçmiş hafiza değil, erken ve canlı tepki daha değerli.
    if module in ("V_DIP_RECOVERY", "DIP_SWEEP"):
        score += 40
    elif module in ("DIP_REACTION", "ELITE_WHALE"):
        score += 36
    elif module == "EARLY_REVERSAL":
        score += 34
    elif module == "ROCKET":
        score += 34
    elif module == "SQUEEZE_EXPLOSION":
        score += 26
    elif module == "EARLY_CONFIRM":
        score += 24
    elif module == "SAFE":
        score += 24
    elif module == "MONEY":
        score += 20
    elif module == "TREND_BUILDUP":
        score += 18
    elif module == "SQUEEZE":
        score += 16
    elif module == "DIP":
        score += 16
    elif module == "WATCH":
        score += 12
    elif module == "EARLY":
        score += 10
    elif module == "HISTORY_BUILDUP":
        score += 8
    elif module == "WAKEUP":
        score += 2
    elif module == "REVERSAL":
        score += 12
    elif module == "MOMENTUM":
        # Momentum tek basina gec sinyal olabilir; dusuk agirlik.
        score += 2

    # Bir coinde birden fazla radar ayni anda yaniyorsa kalite artar.
    if "V_DIP_RECOVERY" in s or "DIP_SWEEP" in s:
        score += 22
    if "DIP_REACTION" in s or "DIP" in s or "ELITE_WHALE" in s:
        score += 18
    if "EARLY_REVERSAL" in s:
        score += 18
    if "ROCKET" in s:
        score += 18
    if "SQUEEZE_EXPLOSION" in s:
        score += 12
    if "SQUEEZE" in s:
        score += 8
    if "TREND_BUILDUP" in s:
        score += 9
    if "MONEY" in s:
        score += 6
    if "SAFE" in s:
        score += 8
    if "EARLY_CONFIRM" in s:
        score += 8
    if "EARLY" in s:
        score += 4
    if "REVERSAL" in s:
        score += 6
    if "HISTORY_BUILDUP" in s:
        score += 4
    if "MOMENTUM" in s:
        score += 0

    # Radar sayisi da onemli ama asil deger erken radarlarin birlikte yanmasi.
    score += min(len(support_modules), 4) * 5
    if {"EARLY", "MONEY"}.issubset(s):
        score += 10
    if {"EARLY", "SQUEEZE"}.issubset(s):
        score += 8
    if {"MONEY", "SAFE"}.issubset(s):
        score += 10
    if {"TREND_BUILDUP", "MONEY"}.issubset(s):
        score += 10
    if {"TREND_BUILDUP", "SQUEEZE"}.issubset(s):
        score += 8
    return score



def mexc_relative_market_gate_ok(best, support=None):
    """
    V21 COIN HACMINE GORE ELITE FILTRESI:
    Sinyal hacmi coinin kendi 24s hacmine gore anlamli degilse Elite AL sayisini azaltir.
    Ama BSB/XPL/LIT gibi para hafizasi guclu coinleri kacirmamak icin memory istisnasi vardir.
    """
    if not best:
        return False

    support = support or []
    module = best.get("module", "UNKNOWN")
    market_now = float(best.get("market_impact_pct", 0) or 0)
    market_quality = max(
        market_now,
        float(best.get("history_market_max", 0) or 0),
        float(best.get("money_memory_market_60m", 0) or 0),
    )
    usdt_vol = float(best.get("usdt_vol", best.get("signal_usdt_vol", 0)) or 0)
    money = float(best.get("money_impact", 0) or 0)
    power = float(best.get("volume_power", 0) or 0)
    waves = int(best.get("money_memory_waves_60m", 0) or 0)
    mem_bonus = bool(best.get("money_memory_bonus") or money_memory_buildup_ok(best))
    long_mem = bool(history_long_memory_bonus_ok(best))
    total_market_60m = float(best.get("money_memory_market_60m", 0) or 0)

    strong_memory = (
        mem_bonus
        and waves >= MONEY_MEMORY_MIN_WAVES
        and total_market_60m >= MEXC_ELITE_STRONG_MEMORY_MARKET_60M
    )
    strong_abs_money = (
        usdt_vol >= MEXC_ELITE_STRONG_ABS_USDT
        and money >= 2.0
        and power >= 5.0
    )

    # Dip/sweep/V-dip sinyallerinde anlik market etki bazen dusuk kalabilir; yine de minimum etki aransin.
    if module in ("DIP", "DIP_REACTION", "DIP_SWEEP", "ELITE_WHALE", "V_DIP_RECOVERY"):
        return (
            market_now >= MEXC_ELITE_DIP_MIN_MARKET_IMPACT
            or usdt_vol >= 75_000
            or strong_memory
        )

    # HISTORY_BUILDUP icin tek mum degil, 60dk toplam market etkisi ve radar hafizasi dikkate alinir.
    if module == "HISTORY_BUILDUP":
        return (
            market_quality >= MEXC_ELITE_MIN_HISTORY_MARKET_QUALITY
            or strong_memory
            or long_mem
            or strong_abs_money
        )

    # SQUEEZE_EXPLOSION zaten ayrica kalite filtresinden geciyor; burada coin hacmine gore zayif kalanlari kes.
    if module == "SQUEEZE_EXPLOSION":
        return (
            market_now >= MEXC_ELITE_MIN_MARKET_IMPACT
            or strong_memory
            or strong_abs_money
        )

    # Genel AL kapisi: coin hacmine gore anlamli etki ya da guclu para hafizasi/absolute para lazim.
    return (
        market_now >= MEXC_ELITE_MIN_MARKET_IMPACT
        or strong_memory
        or strong_abs_money
    )

def entry_quality_score(d, support_modules=None, btc_status=""):
    """
    Elite artik 'gucu' degil 'giris kalitesini' puanlar.
    FOMO, yuksek RSI ve gec momentum cezalandirilir.
    """
    support_modules = support_modules or []
    module = d.get("module", "UNKNOWN")
    score = 0

    rs = d.get("rs", 0)
    base_score = d.get("score", 0)
    money = d.get("money_impact", 0)
    power = d.get("volume_power", 0)
    vol_ratio = d.get("vol_ratio", 0)
    usdt_vol = d.get("usdt_vol", 0)
    market_impact_pct = d.get("market_impact_pct", 0)
    market_impact_score = d.get("market_impact_score", 0)
    rsi_value = d.get("rsi", d.get("rsi15", 0))
    dist = d.get("dist_from_low", 999)
    price_gain = d.get("price_gain_from_first", 0)
    fomo = fomo_gain_pct(d)
    fomo_exempt = module == "V_DIP_RECOVERY" or d.get("fomo_exempt", False) or bool(d.get("trend_continuation_ok"))

    score += radar_support_score(module, support_modules)

    if d.get("trend_continuation_ok"):
        score += int(d.get("trend_continuation_bonus", 0) or 0)
        if module == "TREND_BUILDUP":
            score += 6

    if base_score >= 14:
        score += 10
    elif base_score >= 12:
        score += 8
    elif base_score >= 10:
        score += 6
    elif base_score >= 8:
        score += 4

    if rs >= 85:
        score += 10
    elif rs >= 75:
        score += 8
    elif rs >= 65:
        score += 6
    elif rs >= 55:
        score += 4
    elif rs >= 45:
        score += 2

    # Para gucu iyi ama tek basina yetmez.
    if money >= 2.4:
        score += 12
    elif money >= 1.8:
        score += 9
    elif money >= 1.45:
        score += 7
    elif money >= 1.20:
        score += 4

    if power >= 5.0:
        score += 12
    elif power >= 3.5:
        score += 9
    elif power >= 2.5:
        score += 7
    elif power >= 1.8:
        score += 4

    if vol_ratio >= 2.2:
        score += 7
    elif vol_ratio >= 1.6:
        score += 5
    elif vol_ratio >= 1.3:
        score += 3

    if usdt_vol >= 100000:
        score += 8
    elif usdt_vol >= 50000:
        score += 6
    elif usdt_vol >= 20000:
        score += 4
    elif usdt_vol >= 8000:
        score += 2

    # Coin hacmine gore gercek para etkisi. Buyuk coinlerde kucuk hacim abartilmasin,
    # kucuk/orta coinlerde goreceli guclu para girisi odullendirilsin.
    if market_impact_pct >= 1.0:
        score += 14
    elif market_impact_pct >= 0.50:
        score += 11
    elif market_impact_pct >= 0.25:
        score += 8
    elif market_impact_pct >= 0.12:
        score += 5
    elif market_impact_pct >= 0.06:
        score += 2
    elif usdt_vol < 50000:
        score -= 6

    if market_impact_score >= 78:
        score += 4
    elif market_impact_score <= 15 and usdt_vol < 50000:
        score -= 4

    # V28 ZORA FIX: Çok düşük canlı USDT + düşük market etki Elite puanını şişirmesin.
    # PRL gibi küçük para ama %1+ market etki yapan coinler bu cezayı yemez.
    if usdt_vol < MEXC_MIN_LIVE_USDT_FOR_ELITE and market_impact_pct < MEXC_MIN_LOW_USDT_MARKET_IMPACT and not squeeze_fast_pre_elite_ok(d):
        score -= 20
        if module in ("SQUEEZE_EXPLOSION", "SQUEEZE", "HISTORY_BUILDUP"):
            score -= 10

    # V21: Coin hacmine gore etki zayifsa puan sisirmesin.
    # Bu, hacmi cok buyuk coinlerde kucuk para akisinin 100/100 yapmasini azaltir.
    market_quality_for_score = max(market_impact_pct, d.get("history_market_max", 0), d.get("money_memory_market_60m", 0))
    if market_quality_for_score >= 20:
        score += 8
    elif market_quality_for_score >= 5:
        score += 5
    elif market_quality_for_score >= 1:
        score += 2
    elif market_impact_pct < 0.20 and usdt_vol < MEXC_ELITE_STRONG_ABS_USDT and not squeeze_fast_pre_elite_ok(d):
        score -= 12

    # Para Kalitesi Terfisi: H gibi tek radar ama cok guclu para girisi olanlari odullendir.
    if money_quality_upgrade(d):
        score += 22

    # V20 BSB/SILVER FIX: kaliteli SQUEEZE_EXPLOSION odullensin, zayif ust fitilli squeeze cezalandirilsin.
    if module == "SQUEEZE_EXPLOSION":
        if squeeze_fast_pre_elite_ok(d):
            score += SQUEEZE_FAST_ELITE_BONUS
            d["squeeze_fast_pre_elite"] = True
        elif squeeze_explosion_elite_exception(d):
            score += 18
        else:
            score -= 18

    # Erken giris odulu.
    if dist <= 3:
        score += 14
    elif dist <= 6:
        score += 10
    elif dist <= 10:
        score += 6
    elif dist <= 14:
        score += 3

    # FOMO cezasi: gec gelen patlama mumu Elite olmasin.
    if not fomo_exempt:
        if d.get("price_gain_15m", 0) > 8:
            score -= 12
        if d.get("price_gain_30m", 0) > 15:
            score -= 12

        if fomo > 25:
            score -= 35
        elif fomo > 18:
            score -= 25
        elif fomo > 12:
            score -= 15
        elif fomo > 8:
            score -= 8

    # Momentum gec geldiyse sert ceza. Momentum tek basina Elite degildir.
    if module == "MOMENTUM":
        if not any(x in support_modules for x in ("EARLY", "MONEY", "SAFE", "SQUEEZE")):
            score -= 35
        if price_gain > 2.8:
            score -= 40
        elif price_gain > 2.0:
            score -= 28
        elif price_gain > 1.4:
            score -= 16
        else:
            score -= 6

    # RSI cezasi.
    if rsi_value >= 82:
        score -= 25
    elif rsi_value >= 78:
        score -= 15
    elif rsi_value >= 74:
        score -= 8

    if btc_status == "BTC ZAYIF":
        score -= 10

    # Destekleyici teknikler.
    if d.get("obv_up"):
        score += 8
    if d.get("macd_turn") or d.get("macd_bull") or d.get("macd_cross_near"):
        score += 6
    if d.get("bb_expanding") or d.get("range_break") or d.get("upper_break"):
        score += 5
    if d.get("deep_sweep"):
        score += 8
    if d.get("close_back_inside"):
        score += 5

    # V32: Sentetik delta / alici baskisi.
    # Para ve hacim yuksek ama OBV/MACD/EMA tarafinda alici baskisi yoksa Elite puani dusur.
    flow_score = int(d.get("flow_score", 0) or 0)
    if flow_score >= FLOW_SCORE_STRONG:
        score += FLOW_STRONG_ELITE_BONUS
    elif money >= 2.0 and power >= 5.0 and flow_score < 3:
        score -= FLOW_WEAK_ELITE_PENALTY

    if module == "TREND_BUILDUP":
        pc6 = d.get("price_change_6h", 0)
        pc12 = d.get("price_change_12h", 0)
        if 2 <= pc6 <= 14:
            score += 12
        elif pc6 > 18:
            score -= 18
        if pc12 > 35:
            score -= 20
        if d.get("higher_low_count", 0) >= 3:
            score += 8
        if d.get("close_above_ema21_count", 0) >= 8:
            score += 8
        if d.get("obv_up"):
            score += 8
        if d.get("market_impact_pct", 0) >= 0.10:
            score += 6

    if module == "V_DIP_RECOVERY":
        if d.get("drop_from_high", 0) >= 20:
            score += 10
        if 8 <= d.get("recovery_from_low", 0) <= 35:
            score += 12
        if d.get("still_below_high", 999) >= 15:
            score += 8
        if d.get("deep_sweep") or d.get("touched_bb"):
            score += 8
        if d.get("reclaim_ema9") or d.get("reclaim_mid"):
            score += 6
        if d.get("market_impact_pct", 0) >= 0.10 or d.get("usdt_vol", 0) >= 100000:
            score += 8
        if d.get("fast_liquidity_sweep"):
            score += 16
        if d.get("recovery_ratio", 0) >= 0.80:
            score += 6
        if d.get("vol_ratio", 0) >= 1.50:
            score += 5

    if module == "HISTORY_BUILDUP":
        hp = d.get("history_points", 0)
        market_quality = max(d.get("market_impact_pct", 0), d.get("history_market_max", 0), d.get("money_memory_market_60m", 0))
        power_quality = max(d.get("volume_power", 0), d.get("history_power_max", 0), d.get("money_memory_power_max", 0))
        mem_ok = money_memory_buildup_ok(d)

        if hp >= 22:
            score += 20
        elif hp >= 18:
            score += 16
        elif hp >= HISTORY_BUILDUP_MIN_POINTS:
            score += 10

        if history_long_memory_bonus_ok(d):
            score += 12
        if mem_ok:
            score += 14

        # Para gucu olmadan HISTORY_BUILDUP Elite puani sisirmesin.
        if power_quality >= 8:
            score += 4
        elif power_quality >= 4:
            score += 2

        if market_quality >= 2.0:
            score += 4
        elif market_quality >= 1.0:
            score += 2

        if not history_long_memory_bonus_ok(d):
            if power_quality < 3:
                score -= 15
            if market_quality < 1.0:
                score -= 10
        if d.get("history_price_gain", 0) > HISTORY_BUILDUP_MAX_GAIN:
            score -= 15
        if not history_buildup_quality_ok(d):
            score -= 25

    # V30: Ana kanal tekrar hafizasi. 3-5 kez israrli radar gelen coin Elite'e yaklasir.
    main_bonus = int(d.get("main_signal_bonus", 0) or 0)
    if main_bonus:
        score += min(25, main_bonus)
        if module == "HISTORY_BUILDUP":
            score += 6

    # V31: Hafizada coin + yeni para/hacim = ikinci firsat.
    if second_wave_bonus_ok(d):
        score += SECOND_WAVE_BONUS
    if memory_reentry_bonus_ok(d):
        score += MEMORY_REENTRY_BONUS
        if module == "HISTORY_BUILDUP":
            score += 6

    # V31: Zayif para etkili Elite'leri temizle. Guclu hafiza/second wave varsa ceza yemez.
    strong_memory_context = (
        memory_reentry_bonus_ok(d)
        or second_wave_bonus_ok(d)
        or d.get("money_memory_bonus")
        or d.get("history_long_memory_bonus")
        or int(d.get("main_signal_count_120m", 0) or 0) >= 5
    )
    if not strong_memory_context and money < WEAK_MONEY_MIN_MONEY and power < WEAK_MONEY_MIN_POWER:
        score -= WEAK_MONEY_ELITE_PENALTY

    # V37: Destek / direnÃ§ filtresi. Dirence yapisik AL sinyalini cezalandir,
    # kirilmis direnÃ§ ve destek ustu girisi odullendir.
    if d.get("sr_ok"):
        sr_penalty = int(d.get("sr_penalty", 0) or 0)
        sr_bonus = int(d.get("sr_bonus", 0) or 0)
        # Dip/V toparlanma sinyallerinde direnc cezasi yariya iner; ana risk destekten tepkiyi kacirmamaktir.
        if module in ("DIP", "DIP_REACTION", "DIP_SWEEP", "ELITE_WHALE", "V_DIP_RECOVERY"):
            sr_penalty = int(sr_penalty * 0.50)
        score += sr_bonus
        score -= sr_penalty

    # V43: Order book / order flow / likidite boslugu Elite puan etkisi.
    ob_score = int(d.get("orderbook_score", 50) or 50)
    of_score = int(d.get("order_flow_score", 50) or 50)
    gap_score = int(d.get("liquidity_gap_score", 50) or 50)
    squeeze_proxy = int(d.get("squeeze_proxy_score", 50) or 50)
    whale_sweep = int(d.get("whale_sweep_score", 50) or 50)
    if d.get("orderbook_block"):
        score -= 24
    elif ob_score >= 72:
        score += MEXC_OB_SCORE_BONUS_STRONG
    elif ob_score >= 60:
        score += MEXC_OB_SCORE_BONUS_OK
    elif ob_score <= 42:
        score -= MEXC_OB_SCORE_PENALTY_WEAK

    if of_score >= MEXC_ORDER_FLOW_STRONG:
        score += 10
    elif of_score <= MEXC_ORDER_FLOW_WEAK:
        score -= 12

    if gap_score >= MEXC_LIQ_GAP_STRONG:
        score += 8
    elif gap_score <= 35:
        score -= 8

    if squeeze_proxy >= MEXC_SQUEEZE_PROXY_STRONG:
        score += 8
    if whale_sweep >= MEXC_WHALE_SWEEP_STRONG and module in ("V_DIP_RECOVERY", "EARLY_REVERSAL", "DIP_REACTION", "DIP", "ELITE_WHALE"):
        score += 10

    # V26: Canli momentum cezasi. Hafiza puani, son mumdaki zayifligi ezmesin.
    score -= int(d.get("live_penalty", 0) or 0)

    # V41: Grafik-teknik uyumsuzluk cezasi. Teknik guclu ama grafik zayifsa puan dusur.
    score -= int(d.get("gtu_penalty", 0) or 0)

    # V46: Elite Guven Skoru son karar puanina kontrollu etki eder.
    conf = int(d.get("elite_confidence_score", 50) or 50)
    if conf >= 82:
        score += 10
    elif conf >= MEXC_ELITE_CONFIDENCE_BONUS_SCORE:
        score += 6
    elif conf < MEXC_ELITE_CONFIDENCE_BLOCK_SCORE:
        score -= 18
    elif conf < MEXC_ELITE_CONFIDENCE_WARN_SCORE:
        score -= 8

    return max(0, min(100, int(score)))


def entry_decision_allowed(best, support=None, btc_status=""):
    """
    Telegram'a AL olarak gidecek sinyalin kapisi.
    Gec momentum ve FOMO mumlari burada elenir.
    """
    support = support or []
    module = best.get("module", "UNKNOWN")
    rs = best.get("rs", 0)
    money = best.get("money_impact", 0)
    power = best.get("volume_power", 0)
    vol_ratio = best.get("vol_ratio", 0)
    usdt_vol = best.get("usdt_vol", 0)
    market_impact_pct = best.get("market_impact_pct", 0)
    market_impact_score = best.get("market_impact_score", 0)
    rsi_value = best.get("rsi", best.get("rsi15", 0))
    dist = best.get("dist_from_low", 999)
    price_gain = best.get("price_gain_from_first", 0)
    fomo = signal_price_gain_pct(best)
    support_set = set(support)
    fomo_exempt = module == "V_DIP_RECOVERY" or best.get("fomo_exempt", False)

    if rsi_value >= 82:
        return False

    # V28 ZORA FIX: Canli para cok dusuk ve market etki %1 altindaysa Elite'e gönderme.
    # Dip/V-dip/fast liquidity sweep istisna; PRL tipi %1+ market etki yapan kucuk coinler gecmeye devam eder.
    low_live_money = (
        usdt_vol < MEXC_MIN_LIVE_USDT_FOR_ELITE
        and market_impact_pct < MEXC_MIN_LOW_USDT_MARKET_IMPACT
    )
    low_money_exempt = (
        module in ("V_DIP_RECOVERY", "DIP_SWEEP", "DIP_REACTION", "DIP", "ELITE_WHALE")
        or best.get("fast_liquidity_sweep")
        or squeeze_fast_pre_elite_ok(best)
    )
    if low_live_money and not low_money_exempt:
        return False

    # FOMO filtresi: normal pump gec kaldiyse AL mesaji yok.
    # V_DIP_RECOVERY icin gevsek; cunku once sert dump vardir, toparlanma FOMO sayilmaz.
    if not fomo_exempt:
        if best.get("price_gain_15m", 0) > 8:
            return False
        if best.get("price_gain_30m", 0) > 15:
            return False
        if fomo > 12:
            return False

    # V21 Coin hacmine gore para etkisi kapisi.
    # Mutlak hacim tek basina yeterli degil; sinyal coinin 24s hacmine gore de anlamli olmali.
    if not mexc_relative_market_gate_ok(best, support):
        return False

    # V37: Destek/direnÃ§ kapisi. Para var diye direncin hemen altinda AL basma.
    if not sr_elite_gate_ok(best):
        return False

    # V41: Grafik-teknik uyumsuzsa Elite AL verme.
    if best.get("gtu_block"):
        return False

    # Elite icin radar kombinasyonu: genel olarak 3 radar veya guclu erken/dip istisnasi gerekir.
    if not elite_combo_allowed(best, support):
        return False

    # Para Kalitesi Terfisi: H ornegi gibi cok guclu para girisi olan tek radarlar AL kapisina aday olabilir.
    if money_quality_upgrade(best):
        return (
            module != "MOMENTUM"
            and money >= 2.0
            and power >= 5.0
            and (usdt_vol >= 75_000 or market_impact_pct >= 1.0)
            and rsi_value <= 72
            and fomo <= 12
        )

    # Momentum artik tek basina AL degil. Erken radarlarla destekli ve kacmamis olmali.
    if module == "MOMENTUM":
        return (
            price_gain <= 1.4
            and fomo <= 8
            and money >= 1.8
            and power >= 3.5
            and usdt_vol >= 25000
            and len(support_set.intersection({"MONEY", "EARLY", "SAFE", "SQUEEZE"})) >= 2
            and rsi_value <= 70
        )

    if module == "SAFE":
        return (
            best.get("confidence", best.get("score", 0)) >= 70
            and money >= 1.35
            and power >= 2.6
            and usdt_vol >= 25000
            and market_impact_pct >= 0.05
            and rsi_value <= 74
            and fomo <= 10
            and best.get("dist_from_low", 999) <= 12
        )

    if module == "EARLY_CONFIRM":
        return (
            1.2 <= price_gain <= 5.5
            and money >= 1.45
            and power >= 2.7
            and usdt_vol >= 15000
            and market_impact_pct >= 0.05
            and rsi_value <= 70
            and best.get("price_gain_15m", 0) <= 8
            and best.get("price_gain_30m", 0) <= 15
            and fomo <= 8
        )

    if module == "MONEY":
        return (
            money >= 1.45
            and power >= 2.8
            and usdt_vol >= 15000
            and market_impact_pct >= 0.05
            and price_gain <= 2.0
            and fomo <= 8
            and rsi_value <= 72
            and (("EARLY" in support_set) or ("SAFE" in support_set) or ("SQUEEZE" in support_set) or len(support) >= 1)
        )

    if module == "WATCH":
        return (
            money >= 1.25
            and power >= 2.2
            and best.get("watch_price_gain", 0) <= 1.6
            and rsi_value <= 72
            and len(support) >= 1
        )

    if module == "EARLY":
        return (
            money >= 1.35
            and power >= 2.4
            and usdt_vol >= 25000
            and market_impact_pct >= 0.05
            and dist <= 12
            and rsi_value <= 70
            and len(support) >= 2
        )

    if module == "TREND_BUILDUP":
        return (
            1.2 <= best.get("price_change_6h", 0) <= 18
            and best.get("price_change_12h", 0) <= 45
            and best.get("higher_low_count", 0) >= 2
            and best.get("close_above_ema21_count", 0) >= 7
            and money >= 1.15
            and power >= 1.6
            and usdt_vol >= 12000
            and market_impact_pct >= 0.04
            and 45 <= rsi_value <= 72
            and fomo <= 10
            and (best.get("obv_up") or best.get("macd_turn"))
        )

    if module == "HISTORY_BUILDUP":
        market_quality = max(market_impact_pct, best.get("history_market_max", 0), best.get("money_memory_market_60m", 0), best.get("main_signal_market_max", 0))
        power_quality = max(power, best.get("history_power_max", 0), best.get("money_memory_power_max", 0), best.get("main_signal_power_max", 0))
        mem_ok = money_memory_buildup_ok(best)
        second_wave_ok = second_wave_bonus_ok(best)
        memory_reentry_ok = memory_reentry_bonus_ok(best)
        main_repeat_ok = (
            best.get("main_signal_count_60m", 0) >= 3
            or best.get("main_signal_count_120m", 0) >= 5
        )
        normal_history_ok = (
            history_buildup_quality_ok(best)
            and (money >= 1.25 or best.get("history_money_max", 0) >= 1.8)
            and (power >= 2.2 or power_quality >= HISTORY_BUILDUP_MIN_VOLUME_POWER)
            and (market_quality >= HISTORY_BUILDUP_MIN_MARKET_IMPACT or power_quality >= HISTORY_BUILDUP_MIN_VOLUME_POWER)
            and rsi_value <= HISTORY_BUILDUP_MAX_RSI
        )
        # V30: Ana kanal 3-5 kez ayni coini israrla yakaliyorsa HISTORY_BUILDUP kapisi daha esnek.
        # Yine de aşırı RSI/FOMO tepesinde AL basmaz.
        main_repeat_history_ok = (
            main_repeat_ok
            and rsi_value <= 78
            and fomo <= 18
            and (
                power_quality >= 3.0
                or market_quality >= 0.50
                or best.get("main_signal_count_120m", 0) >= 8
            )
            and (best.get("obv_up") or best.get("macd_turn") or best.get("bb_expanding") or best.get("main_signal_unique_count", 0) >= 2)
        )
        long_memory_ok = history_long_memory_bonus_ok(best)
        return (
            (normal_history_ok or long_memory_ok or mem_ok or main_repeat_history_ok or second_wave_ok or memory_reentry_ok)
            and (best.get("obv_up") or best.get("macd_turn") or best.get("bb_expanding") or "SQUEEZE" in support_set or "TREND_BUILDUP" in support_set or "SQUEEZE_EXPLOSION" in support_set or "MONEY" in support_set or long_memory_ok or main_repeat_history_ok or second_wave_ok or memory_reentry_ok)
        )

    if module == "SQUEEZE":
        return (
            money >= 1.5
            and power >= 3.0
            and vol_ratio >= 1.5
            and usdt_vol >= 25000
            and market_impact_pct >= 0.05
            and dist <= 12
            and rsi_value <= 76
            and (best.get("obv_up") or best.get("macd_turn"))
        )

    if module == "SQUEEZE_EXPLOSION":
        # V20: SILVER filtresi. Sadece kaliteli squeeze patlamasi AL kapisindan gecer.
        return squeeze_explosion_elite_exception(best)

    if module in ("DIP", "DIP_REACTION", "DIP_SWEEP", "ELITE_WHALE", "V_DIP_RECOVERY"):
        fast_sweep_gate = (
            module == "V_DIP_RECOVERY"
            and best.get("fast_liquidity_sweep")
            and dist <= 12
            and money >= 1.05
            and power >= 1.20
            and (market_impact_pct >= 0.03 or usdt_vol >= 25000)
            and rsi_value <= 64
            and (best.get("obv_up") or best.get("macd_turn") or best.get("green_reaction") or best.get("reclaim_ema9"))
        )
        normal_dip_gate = (
            dist <= 7
            and money >= 1.25
            and power >= 2.0
            and (market_impact_pct >= 0.05 or usdt_vol >= 75000)
            and rsi_value <= 62
            and (best.get("obv_up") or best.get("macd_turn") or best.get("green_reaction"))
        )
        return normal_dip_gate or fast_sweep_gate

    return False


def select_best_signal(signals):
    if not signals:
        return None

    # Oncelik artik "en yuksek momentum" degil, "en iyi giris kalitesi".
    decorated = []
    for s in signals:
        support = [x["module"] for x in signals if x["module"] != s["module"]]
        decorated.append((entry_quality_score(s, support), len(support), s.get("priority", 0), s.get("score", 0), s))
    return sorted(decorated, reverse=True)[0][-1]


def send_selected_signal(symbol, signals, funding, btc_status):
    if not signals:
        return False
    # V51: Ana kanal tekrar hafizasi secimden once sinyallere islenir.
    record_main_signal_memory(symbol, signals)
    for _sig in signals:
        attach_main_signal_summary(symbol, _sig)
    best = select_best_signal(signals)
    support = [s["module"] for s in signals if s["module"] != best["module"]]
    cooldown_map = {"ELITE_HAZIRLIK":(sent_elite_hazirlik, COOLDOWN_ELITE_HAZIRLIK), "PRE_ROCKET_WATCH":(sent_pre_rocket_watch, COOLDOWN_PRE_ROCKET_WATCH), "EARLY_CONFIRM":(sent_early_confirm, COOLDOWN_EARLY_CONFIRM), "TREND_BUILDUP":(sent_trend_buildup, COOLDOWN_TREND_BUILDUP), "V_DIP_RECOVERY":(sent_v_dip_recovery, COOLDOWN_V_DIP_RECOVERY), "HISTORY_BUILDUP":(sent_radar_history, COOLDOWN_RADAR_HISTORY), "SQUEEZE_EXPLOSION":(sent_squeeze_explosion, COOLDOWN_SQUEEZE_EXPLOSION), "ROCKET":(sent_rocket_radar, COOLDOWN_ROCKET_RADAR), "SAFE":(sent_safe, COOLDOWN_SAFE), "MOMENTUM":(sent_momentum_continue, COOLDOWN_MOMENTUM_CONTINUE), "MONEY":(sent_money_continue, COOLDOWN_MONEY_CONTINUE), "WATCH":(sent_watch_confirm, COOLDOWN_WATCH_CONFIRM), "DIP":(sent_dip, COOLDOWN_DIP), "DIP_REACTION":(sent_dip_reaction, COOLDOWN_DIP_REACTION), "DIP_SWEEP":(sent_strong_wick_watch, COOLDOWN_STRONG_WICK_WATCH), "ELITE_WHALE":(sent_elite_whale, MEXC_ELITE_COOLDOWN), "STRONG_WICK":(sent_strong_wick_watch, COOLDOWN_STRONG_WICK_WATCH), "REVERSAL":(sent_reversal_watch, COOLDOWN_REVERSAL_WATCH), "SQUEEZE":(sent_squeeze_breakout, COOLDOWN_SQUEEZE_BREAKOUT), "EARLY":(sent_early, COOLDOWN_EARLY)}
    cache, cooldown = cooldown_map.get(best["module"], (sent_early, COOLDOWN_EARLY))
    if best["module"] == "EARLY" and not can_send_early_today(symbol):
        print("EARLY DAILY LIMIT:", symbol, "Limit:", EARLY_MAX_PER_SYMBOL_PER_DAY, flush=True)
        return False

    if can_send(cache, symbol + "_" + best["module"], cooldown):
        # V35: Elite Hazirlik / Pre-Rocket takip mesajlari ayri kanala gider.
        # Bunlar AL degildir; Elite Gold kanalina zorlanmaz ve ana kanali doldurmaz.
        if best["module"] in ("ELITE_HAZIRLIK", "PRE_ROCKET_WATCH"):
            attach_support_resistance_context(symbol, best)
            send_telegram(format_signal(symbol, best, funding, btc_status, support), MEXC_ELITE_PREP_CHAT_ID)
            print("SEND PREP:", symbol, best["module"], "Score:", best.get("score"), "Support:", support, flush=True)
            return True

        # Once Elite kapisini kontrol et.
        # Elite'e giderse ana kanala kopyalama yapma.
        if send_mexc_elite_signal(symbol, best, support, btc_status):
            if best["module"] == "EARLY":
                mark_early_sent_today(symbol)
            print("SEND ELITE ONLY:", symbol, best["module"], "Score:", best.get("score"), "Support:", support, flush=True)
            return True

        if best["module"] == "ELITE_WHALE":
            print("ELITE_WHALE RED MAIN GONDERILMEDI:", symbol, "Score:", best.get("score"), "Support:", support, flush=True)
            return False

        send_telegram(format_signal(symbol, best, funding, btc_status, support))

        if best["module"] == "EARLY":
            mark_early_sent_today(symbol)

        print("SEND MAIN:", symbol, best["module"], "Score:", best.get("score"), "Support:", support, flush=True)
        return True
    print("COOLDOWN:", symbol, best["module"], "Support:", support, flush=True)
    return False


def analyze(item, btc_ok, btc_status):
    symbol = item["symbol"]
    rs = item["rs_score"]
    daily_qv = item.get("qv", 0)
